// =====================================
// QRコード
// =====================================
let qrLib = null;
function loadQR() {
  if (qrLib) return Promise.resolve(qrLib);
  qrLib = qrcodeGenerator;
  return Promise.resolve(qrLib);
}

function QRView({ value, size = 280 }) {
  const [svg, setSvg] = useState('');
  const [err, setErr] = useState(false);
  useEffect(() => {
    if (!value) return;
    let cancelled = false;
    setErr(false);
    setSvg('');
    loadQR().then(qrcode => {
      if (cancelled) return;
      try {
        const qr = qrcode(0, 'M');
        qr.addData(value);
        qr.make();
        const n = qr.getModuleCount();
        const cell = size / n;
        const margin = cell * 2;
        const total = size + margin * 2;
        let cells = '';
        for (let r = 0; r < n; r++) {
          for (let c = 0; c < n; c++) {
            if (qr.isDark(r, c)) {
              cells += `<rect x="${(c*cell+margin).toFixed(2)}" y="${(r*cell+margin).toFixed(2)}" width="${(cell+0.5).toFixed(2)}" height="${(cell+0.5).toFixed(2)}" fill="${C.ink}"/>`;
            }
          }
        }
        setSvg(`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${total} ${total}" width="${size}" height="${size}" shape-rendering="crispEdges"><rect width="${total}" height="${total}" fill="${C.bgWhite}"/>${cells}</svg>`);
      } catch (e) {
        console.error('QR render failed', e);
        if (!cancelled) setErr(true);
      }
    }).catch((e) => {
      console.error('QR load failed', e);
      if (!cancelled) setErr(true);
    });
    return () => { cancelled = true; };
  }, [value, size]);

  if (err) {
    // 外部画像API（Google Chart API互換）にフォールバック
    const fallbackUrl = `https://api.qrserver.com/v1/create-qr-code/?size=${size}x${size}&data=${encodeURIComponent(value)}`;
    return (
      <img
        src={fallbackUrl}
        alt="QR Code"
        style={{ width: size, height: size, display: 'block' }}
        onError={() => { /* もうどうにもならない */ }}
      />
    );
  }
  if (!svg) return <div style={{ width: size, height: size, display: 'flex', alignItems: 'center', justifyContent: 'center', color: C.inkSub, fontSize: '0.8125rem' }}>生成中…</div>;
  return <div style={{ width: size, height: size, lineHeight: 0 }} dangerouslySetInnerHTML={{ __html: svg }} />;
}

function AccentLine({ height = 3, style = {} }) {
  return <div style={{ height, background: `linear-gradient(90deg, ${C.green} 0%, ${C.green} 33%, ${C.yellow} 33%, ${C.yellow} 66%, ${C.pink} 66%, ${C.pink} 100%)`, ...style }} />;
}

// =====================================
// データフック（シンプル版・無限ループ回避）
// =====================================
function usePosts() {
  const [posts, setPosts] = useState(() => {
    const map = safeLoad(KEYS.posts) || {};
    return Object.values(map).sort((a, b) => b.timestamp - a.timestamp);
  });

  const setFromMap = (map) => {
    safeSave(KEYS.posts, map);
    setPosts(Object.values(map).sort((a, b) => b.timestamp - a.timestamp));
  };

  // Supabase：初回全件取得 + リアルタイム購読
  useEffect(() => {
    if (!supabase) return;
    let mounted = true;

    // 全件取得してlocalStorageとマージ
    supabase.from('posts').select('data').then(({ data, error }) => {
      if (!mounted || error || !data) return;
      const map = safeLoad(KEYS.posts) || {};
      data.forEach(row => { if (row.data?.id) map[row.data.id] = row.data; });
      if (mounted) setFromMap(map);
    });

    // リアルタイム購読（お客様が投稿したら即反映）
    const channel = supabase.channel('posts-realtime')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'posts' }, ({ new: row }) => {
        if (!mounted || !row?.data?.id) return;
        const map = safeLoad(KEYS.posts) || {};
        map[row.data.id] = row.data;
        setFromMap(map);
      })
      .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'posts' }, ({ new: row }) => {
        if (!mounted || !row?.data?.id) return;
        const map = safeLoad(KEYS.posts) || {};
        map[row.data.id] = row.data;
        setFromMap(map);
      })
      .on('postgres_changes', { event: 'DELETE', schema: 'public', table: 'posts' }, ({ old: row }) => {
        if (!mounted || !row?.id) return;
        const map = safeLoad(KEYS.posts) || {};
        delete map[row.id];
        setFromMap(map);
      })
      .subscribe();

    return () => {
      mounted = false;
      supabase.removeChannel(channel);
    };
  }, []);

  const addPost = useCallback((post) => {
    const map = safeLoad(KEYS.posts) || {};
    map[post.id] = post;
    setFromMap(map);
    if (supabase) {
      supabase.from('posts').upsert({ id: post.id, data: post }).catch(console.error);
    }
  }, []);

  const removePost = useCallback((id) => {
    const map = safeLoad(KEYS.posts) || {};
    delete map[id];
    setFromMap(map);
    if (supabase) {
      supabase.from('posts').delete().eq('id', id).catch(console.error);
    }
  }, []);

  const removeAllPosts = useCallback(() => {
    const ids = Object.keys(safeLoad(KEYS.posts) || {});
    setFromMap({});
    if (supabase && ids.length > 0) {
      supabase.from('posts').delete().in('id', ids).catch(console.error);
    }
  }, []);

  const updatePost = useCallback((id, updater) => {
    const map = safeLoad(KEYS.posts) || {};
    if (!map[id]) return;
    const updated = { ...updater(map[id]) };
    map[id] = updated;
    setFromMap(map);
    if (supabase) {
      supabase.from('posts').upsert({ id: updated.id, data: updated }).catch(console.error);
    }
  }, []);

  return { posts, addPost, removePost, removeAllPosts, updatePost };
}

function useStores() {
  const [stores, setStores] = useState(() => {
    const map = safeLoad(KEYS.stores);
    if (!map || Object.keys(map).length === 0) {
      safeSave(KEYS.stores, DEFAULT_STORES);
      return DEFAULT_STORES;
    }
    return map;
  });

  const saveStore = useCallback((store) => {
    const map = safeLoad(KEYS.stores) || {};
    map[store.id] = store;
    safeSave(KEYS.stores, map);
    setStores({ ...map });
  }, []);

  const deleteStore = useCallback((id) => {
    const map = safeLoad(KEYS.stores) || {};
    delete map[id];
    safeSave(KEYS.stores, map);
    setStores({ ...map });
  }, []);

  return { stores, saveStore, deleteStore };
}

// =====================================
// 掲示板用：汎用コレクションフック
// （ゆるく募集 / やってみたい / こんな街 共通）
// =====================================
function useBoard(storageKey, cloudPrefix) {
  const [items, setItems] = useState(() => {
    const map = safeLoad(storageKey) || {};
    return Object.values(map).sort((a, b) => b.timestamp - a.timestamp);
  });

  // 削除済みIDの墓場
  const deletedKey = `mn_deleted_${cloudPrefix}`;
  const deletedIdsRef = useRef(new Set(safeLoad(deletedKey) || []));
  const saveDeleted = () => { try { safeSave(deletedKey, Array.from(deletedIdsRef.current)); } catch {} };

  // クラウド同期
  useEffect(() => {
    let mounted = true;
    const sync = async () => {
      if (typeof window === 'undefined' || !window.storage) return;
      try {
        const result = await window.storage.list(`${cloudPrefix}:`, true);
        if (!result?.keys || !mounted) return;
        const cloudMap = {};
        for (const key of result.keys) {
          const id = key.startsWith(`${cloudPrefix}:`) ? key.slice(cloudPrefix.length + 1) : key;
          if (deletedIdsRef.current.has(id)) {
            window.storage.delete(key, true).catch(() => {});
            continue;
          }
          try {
            const r = await window.storage.get(key, true);
            if (r) {
              const item = JSON.parse(r.value);
              if (item?.id && !deletedIdsRef.current.has(item.id)) cloudMap[item.id] = item;
            }
          } catch {}
        }
        if (!mounted) return;
        const localMap = safeLoad(storageKey) || {};
        const merged = {};
        for (const id in cloudMap) if (!deletedIdsRef.current.has(id)) merged[id] = cloudMap[id];
        for (const id in localMap) {
          if (deletedIdsRef.current.has(id)) continue;
          if (!merged[id] || (localMap[id].updatedAt || 0) >= (merged[id].updatedAt || 0)) {
            merged[id] = localMap[id];
          }
        }
        safeSave(storageKey, merged);
        setItems(Object.values(merged).sort((a, b) => b.timestamp - a.timestamp));
      } catch {}
    };
    sync();
    const t = setInterval(sync, 5000);
    return () => { mounted = false; clearInterval(t); };
  }, [storageKey, cloudPrefix, deletedKey]);

  const addItem = useCallback((item) => {
    if (deletedIdsRef.current.has(item.id)) {
      deletedIdsRef.current.delete(item.id);
      saveDeleted();
    }
    const enriched = { ...item, updatedAt: Date.now() };
    const map = safeLoad(storageKey) || {};
    map[enriched.id] = enriched;
    safeSave(storageKey, map);
    setItems(Object.values(map).sort((a, b) => b.timestamp - a.timestamp));
    if (typeof window !== 'undefined' && window.storage) {
      window.storage.set(`${cloudPrefix}:${enriched.id}`, JSON.stringify(enriched), true).catch(() => {});
    }
  }, [storageKey, cloudPrefix]);

  const updateItem = useCallback((id, updater) => {
    const map = safeLoad(storageKey) || {};
    if (!map[id]) return;
    const updated = { ...updater(map[id]), updatedAt: Date.now() };
    map[id] = updated;
    safeSave(storageKey, map);
    setItems(Object.values(map).sort((a, b) => b.timestamp - a.timestamp));
    if (typeof window !== 'undefined' && window.storage) {
      window.storage.set(`${cloudPrefix}:${id}`, JSON.stringify(updated), true).catch(() => {});
    }
  }, [storageKey, cloudPrefix]);

  const removeItem = useCallback((id) => {
    deletedIdsRef.current.add(id);
    saveDeleted();
    const map = safeLoad(storageKey) || {};
    delete map[id];
    safeSave(storageKey, map);
    setItems(Object.values(map).sort((a, b) => b.timestamp - a.timestamp));
    if (typeof window !== 'undefined' && window.storage) {
      window.storage.delete(`${cloudPrefix}:${id}`, true).catch(() => {});
    }
  }, [storageKey, cloudPrefix]);

  return { items, addItem, updateItem, removeItem };
}

// =====================================
// ギフト商品（クラフトビール）管理
// =====================================
function useGifts() {
  const [gifts, setGifts] = useState(() => {
    const map = safeLoad(KEYS.gifts);
    if (!map || Object.keys(map).length === 0) {
      safeSave(KEYS.gifts, DEFAULT_GIFTS);
      return DEFAULT_GIFTS;
    }
    return map;
  });

  const saveGift = useCallback((gift) => {
    const map = safeLoad(KEYS.gifts) || {};
    map[gift.id] = gift;
    safeSave(KEYS.gifts, map);
    setGifts({ ...map });
  }, []);

  const deleteGift = useCallback((id) => {
    const map = safeLoad(KEYS.gifts) || {};
    delete map[id];
    safeSave(KEYS.gifts, map);
    setGifts({ ...map });
  }, []);

  return { gifts, saveGift, deleteGift };
}

// =====================================
// 投稿タグ管理（管理画面で編集可）
// =====================================
function useTags() {
  const [tags, setTags] = useState(() => {
    const saved = safeLoad(KEYS.tags);
    if (!saved || !Array.isArray(saved) || saved.length === 0) {
      safeSave(KEYS.tags, DEFAULT_TAGS);
      return DEFAULT_TAGS;
    }
    return saved;
  });

  const saveTags = useCallback((newList) => {
    safeSave(KEYS.tags, newList);
    setTags([...newList]);
  }, []);

  const addTag = useCallback((tag) => {
    const list = safeLoad(KEYS.tags) || DEFAULT_TAGS;
    const next = [...list, tag];
    safeSave(KEYS.tags, next);
    setTags(next);
  }, []);

  const updateTag = useCallback((key, updates) => {
    const list = safeLoad(KEYS.tags) || DEFAULT_TAGS;
    const next = list.map(t => t.key === key ? { ...t, ...updates } : t);
    safeSave(KEYS.tags, next);
    setTags(next);
  }, []);

  const deleteTag = useCallback((key) => {
    const list = safeLoad(KEYS.tags) || DEFAULT_TAGS;
    const next = list.filter(t => t.key !== key);
    safeSave(KEYS.tags, next);
    setTags(next);
  }, []);

  const moveTag = useCallback((key, direction) => {
    const list = safeLoad(KEYS.tags) || DEFAULT_TAGS;
    const idx = list.findIndex(t => t.key === key);
    if (idx < 0) return;
    const to = idx + direction;
    if (to < 0 || to >= list.length) return;
    const next = [...list];
    [next[idx], next[to]] = [next[to], next[idx]];
    safeSave(KEYS.tags, next);
    setTags(next);
  }, []);

  return { tags, saveTags, addTag, updateTag, deleteTag, moveTag };
}

