function CountryPicker({ value, onChange }) {
  const [query, setQuery] = useState(value || '');
  const [focused, setFocused] = useState(false);

  useEffect(() => { setQuery(value || ''); }, [value]);

  const filtered = useMemo(() => {
    if (!query.trim()) return COUNTRIES.slice(0, 12);
    const q = query.toLowerCase();
    return COUNTRIES.filter(c =>
      c.name.toLowerCase().includes(q) ||
      c.en.toLowerCase().includes(q)
    ).slice(0, 12);
  }, [query]);

  const select = (c) => {
    setQuery(c.name);
    onChange(c.name);
    setFocused(false);
  };

  return (
    <div style={{ position: 'relative' }}>
      <input
        type="text"
        value={query}
        onChange={(e) => { setQuery(e.target.value); onChange(e.target.value); }}
        onFocus={() => setFocused(true)}
        onBlur={() => setTimeout(() => setFocused(false), 200)}
        placeholder="例：タイ、Korea、🇮🇹..."
        style={s.input}
        autoComplete="off"
      />
      {focused && filtered.length > 0 && (
        <div style={s.countryDropdown}>
          {filtered.map(c => (
            <button
              key={c.name}
              type="button"
              onMouseDown={(e) => { e.preventDefault(); select(c); }}
              style={s.countryItem}
            >
              <span style={{ fontSize: '1.375rem', marginRight: 10 }}>{c.flag}</span>
              <span style={{ fontFamily: FONT_HAND, fontSize: '0.9375rem', fontWeight: 500 }}>{c.name}</span>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

