// =====================================
// 写真ギャラリー（複数写真の左右スライダー）
// =====================================
function PhotoGallery({ photos, onSlideChange }) {
  const [idx, setIdx] = useState(0);
  const list = Array.isArray(photos) && photos.length > 0 ? photos : [];

  const prev = (e) => {
    e?.stopPropagation();
    setIdx(i => {
      const ni = i === 0 ? list.length - 1 : i - 1;
      onSlideChange?.(ni);
      return ni;
    });
  };
  const next = (e) => {
    e?.stopPropagation();
    setIdx(i => {
      const ni = (i + 1) % list.length;
      onSlideChange?.(ni);
      return ni;
    });
  };

  if (list.length === 0) return null;

  return (
    <div style={s.galleryWrap} onClick={(e) => e.stopPropagation()}>
      <img src={list[idx]} alt={`写真${idx + 1}`} style={s.galleryImg}/>
      {list.length > 1 && (
        <>
          <button onClick={prev} style={{ ...s.galleryArrow, left: 6 }}>‹</button>
          <button onClick={next} style={{ ...s.galleryArrow, right: 6 }}>›</button>
          <div style={s.galleryDots}>
            {list.map((_, i) => (
              <span key={i} style={{ ...s.galleryDot, ...(i === idx ? { background: '#fff', width: 18 } : {}) }}/>
            ))}
          </div>
          <div style={s.galleryCounter}>{idx + 1} / {list.length}</div>
        </>
      )}
    </div>
  );
}

function PostDetailModal({ post, updatePost, tagMap, onClose }) {
  const [commentName, setCommentName] = useState('');
  const [commentText, setCommentText] = useState('');
  const [myId] = useState(() => {
    let id = localStorage.getItem('mn_userid');
    if (!id) { id = `u_${Math.random().toString(36).slice(2, 10)}`; localStorage.setItem('mn_userid', id); }
    return id;
  });

  useEffect(() => {
    const saved = localStorage.getItem('mn_penname');
    if (saved) setCommentName(saved);
  }, []);

  const likes = post.likes || [];
  const comments = post.comments || [];
  const liked = likes.includes(myId);

  const toggleLike = () => {
    updatePost(post.id, (cur) => {
      const cl = cur.likes || [];
      return { ...cur, likes: liked ? cl.filter(x => x !== myId) : [...cl, myId] };
    });
  };

  const addComment = () => {
    const name = commentName.trim().slice(0, 20) || '名無し';
    const text = commentText.trim().slice(0, 140);
    if (!text) return;
    try { localStorage.setItem('mn_penname', name); } catch {}
    updatePost(post.id, (cur) => ({
      ...cur,
      comments: [...(cur.comments || []), { name, text, at: Date.now() }]
    }));
    setCommentText('');
  };

  return (
    <div style={s.modalOverlay} onClick={onClose}>
      <div style={{ ...s.modal, maxWidth: 460 }} onClick={(e) => e.stopPropagation()}>
        <div style={{ display: 'flex', gap: 6, marginBottom: 12, flexWrap: 'wrap', alignItems: 'center' }}>
          <span style={{ ...s.miniTag, background: REGION_COLOR(post.region) }}>
            {post.storeName ? `🏠 ${post.storeName}` : post.prefectureName}
          </span>
          {post.detail?.name && <span style={s.miniDetailTag}>📍 {post.detail.name}</span>}
        </div>

        {(post.tags || []).length > 0 && (
          <div style={{ display: 'flex', gap: 4, marginBottom: 12, flexWrap: 'wrap' }}>
            {post.tags.map(tk => {
              const t = (tagMap || {})[tk];
              return t ? <span key={tk} style={{ ...s.postTag, background: t.color + '18', color: t.color }}>{t.emoji}{t.label}</span> : null;
            })}
          </div>
        )}

        {(() => {
          const list = (post.photos && post.photos.length > 0) ? post.photos : (post.photo ? [post.photo] : []);
          if (list.length === 0) return null;
          return <div style={{ marginBottom: 12 }}><PhotoGallery photos={list}/></div>;
        })()}

        <div style={{ fontFamily: FONT_HAND, fontSize: '1rem', lineHeight: 1.7, color: C.ink, marginBottom: 8 }}>{post.message}</div>

        <div style={{ display: 'flex', gap: 6, marginBottom: 12, flexWrap: 'wrap' }}>
          {post.ageGroup && <span style={s.demographicTag}>{post.ageGroup}</span>}
          {post.gender && <span style={s.demographicTag}>{post.gender}</span>}
        </div>

        <div style={{ fontFamily: FONT_HAND, fontSize: '0.75rem', color: C.inkSub, fontStyle: 'italic', marginBottom: 16, textAlign: 'right' }}>— {post.penname}</div>

        {/* いいね */}
        <button onClick={toggleLike} style={{
          ...s.likeBtn,
          background: liked ? C.pinkLight : C.bgWhite,
          borderColor: liked ? C.pink : C.line,
          color: liked ? C.pink : C.inkSub
        }}>
          {liked ? '❤️' : '🤍'} いいね <strong>{likes.length}</strong>
        </button>

        {/* コメント */}
        <div style={{ marginTop: 20, paddingTop: 16, borderTop: `1px dashed ${C.line}` }}>
          <div style={{ fontFamily: FONT_DISPLAY, fontSize: '0.875rem', fontWeight: 700, letterSpacing: 2, marginBottom: 12 }}>
            💬 コメント {comments.length}
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginBottom: 16, maxHeight: 200, overflowY: 'auto' }}>
            {comments.length === 0 ? (
              <div style={{ fontFamily: FONT_HAND, fontSize: '0.75rem', color: C.inkLight, textAlign: 'center', padding: 12 }}>
                最初のコメントを書こう
              </div>
            ) : comments.map((c, i) => (
              <div key={i} style={s.commentItem}>
                <div style={{ fontFamily: FONT_HAND, fontSize: '0.8125rem', color: C.ink, lineHeight: 1.5 }}>{c.text}</div>
                <div style={{ fontFamily: FONT_HAND, fontSize: '0.625rem', color: C.inkSub, marginTop: 4 }}>
                  — {c.name}・{new Date(c.at).toLocaleString('ja-JP', { month: 'numeric', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            ))}
          </div>

          <input type="text" value={commentName} onChange={(e) => setCommentName(e.target.value)} placeholder="ペンネーム" maxLength={20} style={{ ...s.input, marginBottom: 8 }}/>
          <div style={{ display: 'flex', gap: 8 }}>
            <input type="text" value={commentText} onChange={(e) => setCommentText(e.target.value)} placeholder="コメントを書く…" maxLength={140} style={s.input}
              onKeyDown={(e) => { if (e.key === 'Enter') addComment(); }}/>
            <button onClick={addComment} disabled={!commentText.trim()} style={{ ...s.joinFormBtn, background: C.green, opacity: commentText.trim() ? 1 : 0.4 }}>送信</button>
          </div>
        </div>

        <button onClick={onClose} style={{ ...s.modalBtnGhost, width: '100%', marginTop: 16 }}>閉じる</button>
      </div>
    </div>
  );
}

// translateYで動かす方式（scrollTopより確実に動く）
function ScrollingList({ posts, regionColor, onPostClick, tagMap, noAutoScroll = false }) {
  const contentRef = useRef(null);
  const offsetRef = useRef(0);              // 現在の縦オフセット（px、見た目用）
  const lastUserActionRef = useRef(0);
  const [hovering, setHovering] = useState(false);
  const [tick, setTick] = useState(0);      // 再レンダリングトリガー

  const needsScroll = posts.length > 0 && !noAutoScroll;
  // 投稿少なくても確実にループするよう4倍化（必要に応じて）
  const repeats = noAutoScroll ? 1 : (posts.length <= 2 ? 6 : posts.length <= 4 ? 4 : 2);
  const renderList = needsScroll ? Array.from({ length: repeats }, () => posts).flat() : posts;

  // posts変更時にoffsetリセット
  useEffect(() => {
    offsetRef.current = 0;
    setTick(t => t + 1);
  }, [posts.length, posts[0]?.id]);

  // 自動スクロール（毎フレーム）
  useEffect(() => {
    if (!needsScroll) return;
    let raf;
    const speed = 0.4;
    const animate = () => {
      const content = contentRef.current;
      if (content) {
        const recentlyUserScrolled = Date.now() - lastUserActionRef.current < 2000;
        if (!hovering && !recentlyUserScrolled) {
          // 1セット分の高さ（content全体の 1/repeats）
          const oneSet = content.scrollHeight / repeats;
          if (oneSet > 0) {
            offsetRef.current += speed;
            // 1セット分進んだら戻す（継ぎ目なし）
            if (offsetRef.current >= oneSet) {
              offsetRef.current -= oneSet;
            }
            // DOMを直接更新（再レンダリングなし）
            content.style.transform = `translateY(-${offsetRef.current}px)`;
          }
        }
      }
      raf = requestAnimationFrame(animate);
    };
    raf = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(raf);
  }, [needsScroll, hovering, repeats, tick]);

  // 手動スクロール：wheel/touchで offset を直接動かす
  const handleWheel = (e) => {
    e.preventDefault();
    lastUserActionRef.current = Date.now();
    const content = contentRef.current;
    if (!content) return;
    const oneSet = content.scrollHeight / repeats;
    if (oneSet <= 0) return;
    offsetRef.current += e.deltaY;
    // ループ：はみ出したら巻き戻し
    while (offsetRef.current >= oneSet) offsetRef.current -= oneSet;
    while (offsetRef.current < 0) offsetRef.current += oneSet;
    content.style.transform = `translateY(-${offsetRef.current}px)`;
  };

  // タッチ操作
  const touchYRef = useRef(0);
  const handleTouchStart = (e) => {
    touchYRef.current = e.touches[0].clientY;
    lastUserActionRef.current = Date.now();
  };
  const handleTouchMove = (e) => {
    const y = e.touches[0].clientY;
    const dy = touchYRef.current - y;
    touchYRef.current = y;
    lastUserActionRef.current = Date.now();
    const content = contentRef.current;
    if (!content) return;
    const oneSet = content.scrollHeight / repeats;
    if (oneSet <= 0) return;
    offsetRef.current += dy;
    while (offsetRef.current >= oneSet) offsetRef.current -= oneSet;
    while (offsetRef.current < 0) offsetRef.current += oneSet;
    content.style.transform = `translateY(-${offsetRef.current}px)`;
  };

  return (
    <div
      onWheel={handleWheel}
      onTouchStart={handleTouchStart}
      onTouchMove={handleTouchMove}
      onMouseEnter={() => setHovering(true)}
      onMouseLeave={() => setHovering(false)}
      style={{
        flex: 1,
        overflow: 'hidden',
        position: 'relative',
        minHeight: 0
      }}
    >
      {posts.length === 0 ? (
        <div style={{ textAlign: 'center', color: C.inkLight, padding: 40, fontFamily: FONT_HAND }}>
          まだ投稿がありません
        </div>
      ) : (
        <div
          ref={contentRef}
          style={{
            padding: 16,
            display: 'flex',
            flexDirection: 'column',
            gap: 10,
            willChange: 'transform'
          }}
        >
          {renderList.map((post, idx) => {
            const rot = ROTATIONS[idx % ROTATIONS.length] * 0.3;
            const pen = PEN_COLORS[idx % PEN_COLORS.length];
            const likeCount = (post.likes || []).length;
            const commentCount = (post.comments || []).length;
            return (
              <div key={`${post.id}_${idx}`}
                onClick={() => onPostClick && onPostClick(post)}
                style={{
                  ...s.miniPostit,
                  transform: `rotate(${rot}deg)`,
                  color: pen,
                  cursor: onPostClick ? 'pointer' : 'default'
                }}>
                <div style={{ display: 'flex', gap: 6, marginBottom: 8, flexWrap: 'wrap' }}>
                  <span style={{ ...s.miniTag, background: regionColor }}>
                    {post.storeName ? `🏠 ${post.storeName}` : post.prefectureName}
                  </span>
                  {post.detail?.name && (
                    <span style={s.miniDetailTag}>📍 {post.detail.name}</span>
                  )}
                </div>

                {/* タグ */}
                {(post.tags || []).length > 0 && (
                  <div style={{ display: 'flex', gap: 4, marginBottom: 8, flexWrap: 'wrap' }}>
                    {post.tags.map(tk => {
                      const t = (tagMap || {})[tk];
                      if (!t) return null;
                      return <span key={tk} style={{ ...s.postTag, background: t.color + '18', color: t.color }}>{t.emoji}{t.label}</span>;
                    })}
                  </div>
                )}

                {/* 写真表示（1枚目のみ・複数枚はバッジで表示） */}
                {(() => {
                  const list = (post.photos && post.photos.length > 0) ? post.photos : (post.photo ? [post.photo] : []);
                  if (list.length === 0) return null;
                  return (
                    <div style={{ position: 'relative', marginBottom: 10 }}>
                      <img src={list[0]} alt="投稿写真" style={s.miniPostitPhoto}/>
                      {list.length > 1 && (
                        <span style={s.photoCountBadge}>📷 {list.length}枚</span>
                      )}
                    </div>
                  );
                })()}

                <div style={{ fontSize: '1.125rem', lineHeight: 1.7, fontWeight: 500, wordBreak: 'break-word' }}>
                  {post.message}
                </div>

                {/* 年齢層・性別タグ */}
                {(post.ageGroup || post.gender) && (
                  <div style={{ display: 'flex', gap: 4, marginTop: 8, flexWrap: 'wrap' }}>
                    {post.ageGroup && (
                      <span style={s.demographicTag}>{post.ageGroup}</span>
                    )}
                    {post.gender && (
                      <span style={s.demographicTag}>{post.gender}</span>
                    )}
                  </div>
                )}

                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingTop: 8, marginTop: 8, borderTop: '1px dashed ' + pen + '30' }}>
                  <span style={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
                    <span style={{ fontSize: '0.8125rem', fontWeight: 600, fontStyle: 'italic', opacity: 0.7 }}>— {post.penname}</span>
                    {post.timestamp && (
                      <span style={{ fontSize: '0.6875rem', opacity: 0.55, fontFamily: FONT_LATIN, letterSpacing: 0.5 }}>
                        {new Date(post.timestamp).toLocaleString('ja-JP', { month: 'numeric', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
                      </span>
                    )}
                  </span>
                  <span style={{ display: 'flex', gap: 8, fontSize: '0.8125rem', fontWeight: 600, opacity: 0.8 }}>
                    <span>❤️ {likeCount}</span>
                    <span>💬 {commentCount}</span>
                  </span>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* 上下のフェードグラデーション（フェードイン・アウト効果） */}
      {needsScroll && (
        <>
          <div style={{
            position: 'sticky', top: 0, left: 0, right: 0, height: 30,
            marginBottom: -30,
            background: `linear-gradient(to bottom, ${C.bgWhite}, transparent)`,
            pointerEvents: 'none', zIndex: 5
          }} />
          <div style={{
            position: 'sticky', bottom: 0, left: 0, right: 0, height: 30,
            marginTop: -30,
            background: `linear-gradient(to top, ${C.bgWhite}, transparent)`,
            pointerEvents: 'none', zIndex: 5
          }} />
        </>
      )}
    </div>
  );
}

