function AdminScreen({ posts, removePost, removeAllPosts, updatePost, stores, saveStore, deleteStore, settings, updateSettings, events, eventsCtrl, wants, wantsCtrl, cityHopes, cityHopesCtrl, gifts, saveGift, deleteGift, tags, addTag, updateTag, deleteTag, moveTag }) {
  const [tab, setTab] = useState('posts');

  const boardCount = events.length + wants.length + cityHopes.length;

  return (
    <div style={s.adminScreen}>
      <header style={{ display: 'flex', alignItems: 'center', gap: 14, marginBottom: 8 }}>
        <div style={s.adminKanji}>街中</div>
        <div>
          <div style={{ fontFamily: FONT_DISPLAY, fontSize: '1.625rem', fontWeight: 700, letterSpacing: 4 }}>管理画面</div>
          <div style={{ fontFamily: FONT_LATIN, fontSize: '0.6875rem', color: C.inkSub, marginTop: 4, letterSpacing: 3 }}>ADMIN PANEL</div>
        </div>
      </header>

      <AccentLine style={{ margin: '12px 0 20px' }} />

      <div style={s.adminTabs}>
        {[
          ['posts', '📝 マップ投稿', posts.length],
          ['board', '📋 掲示板', boardCount],
          ['tags', '🏷 タグ', tags.length],
          ['gifts', '🍺 商品（ギフト）', Object.keys(gifts).length],
          ['stores', '🏠 お店', Object.keys(stores).length],
          ['settings', '⚙️ 表示設定', null]
        ].map(([key, label, count]) => (
          <button key={key} onClick={() => setTab(key)} style={{ ...s.adminTab, ...(tab === key ? s.adminTabActive : {}) }}>
            {label}
            {count !== null && <span style={s.adminTabCount}>{count}</span>}
          </button>
        ))}
      </div>

      {tab === 'posts' && <PostsTab posts={posts} removePost={removePost} removeAllPosts={removeAllPosts} updatePost={updatePost} stores={stores}/>}
      {tab === 'board' && <BoardAdminTab events={events} eventsCtrl={eventsCtrl} wants={wants} wantsCtrl={wantsCtrl} cityHopes={cityHopes} cityHopesCtrl={cityHopesCtrl}/>}
      {tab === 'gifts' && <GiftsAdminTab gifts={gifts} saveGift={saveGift} deleteGift={deleteGift}/>}
      {tab === 'tags' && <TagsAdminTab tags={tags} addTag={addTag} updateTag={updateTag} deleteTag={deleteTag} moveTag={moveTag}/>}
      {tab === 'stores' && <StoresTab stores={stores} saveStore={saveStore} deleteStore={deleteStore}/>}
      {tab === 'settings' && <SettingsTab settings={settings} updateSettings={updateSettings}/>}
    </div>
  );
}

// =====================================
// 管理：掲示板タブ（3機能の投稿管理 + ギフト会計）
// =====================================
// 削除確認ボタン（インライン確認方式）
function DeleteBtn({ onConfirm, label = '削除' }) {
  const [confirming, setConfirming] = useState(false);
  if (confirming) {
    return (
      <span style={{ display: 'inline-flex', gap: 4 }}>
        <button onClick={() => { onConfirm(); setConfirming(false); }} style={{ ...s.rowBtn, background: C.pink, color: '#fff', borderColor: C.pink, padding: '4px 10px' }}>確定</button>
        <button onClick={() => setConfirming(false)} style={{ ...s.rowBtn, padding: '4px 10px' }}>×</button>
      </span>
    );
  }
  return (
    <button onClick={() => setConfirming(true)} style={{ ...s.rowBtn, color: C.pink, borderColor: C.pink }}>{label}</button>
  );
}

function BoardAdminTab({ events, eventsCtrl, wants, wantsCtrl, cityHopes, cityHopesCtrl }) {
  const [sub, setSub] = useState('events');

  // 未会計ギフトの総数
  const unpaidCount = wants.reduce((sum, w) =>
    sum + (w.gifts || []).filter(g => !g.paid).length, 0);

  return (
    <div>
      <div style={s.boardAdminSubTabs}>
        {[
          ['events', '📣 ゆるく募集', events.length],
          ['wants', '✨ やってみたい', wants.length],
          ['cityHopes', '🌸 こんな街に', cityHopes.length]
        ].map(([key, label, count]) => (
          <button key={key} onClick={() => setSub(key)} style={{ ...s.subTab, ...(sub === key ? s.subTabActive : {}) }}>
            {label} <span style={s.subTabCount}>{count}</span>
          </button>
        ))}
      </div>

      {sub === 'events' && (
        <div>
          {events.length === 0 ? (
            <div style={s.adminEmpty}>募集がありません</div>
          ) : (
            <div style={s.adminCardList}>
              {events.map(ev => (
                <div key={ev.id} style={s.adminCard}>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={s.adminCardTitle}>{ev.title}</div>
                    <div style={s.adminCardMeta}>
                      📅 {new Date(ev.datetime).toLocaleString('ja-JP', { month: 'numeric', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
                      ・📍 {ev.place}・主催 {ev.host}
                    </div>
                    <div style={s.adminCardMeta}>👥 参加 {(ev.participants || []).length}人</div>
                  </div>
                  <DeleteBtn onConfirm={() => eventsCtrl.removeItem(ev.id)}/>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {sub === 'wants' && (
        <div>
          {unpaidCount > 0 && (
            <div style={s.unpaidAlert}>
              🍺 お会計待ちのギフトが <strong>{unpaidCount}件</strong> あります
            </div>
          )}
          {wants.length === 0 ? (
            <div style={s.adminEmpty}>投稿がありません</div>
          ) : (
            <div style={s.adminCardList}>
              {wants.map(w => (
                <div key={w.id} style={{ ...s.adminCard, flexDirection: 'column', alignItems: 'stretch' }}>
                  <div style={{ display: 'flex', gap: 12 }}>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={s.adminCardTitle}>{w.want}</div>
                      <div style={s.adminCardMeta}>📍 {w.regionLabel}・by {w.penname}・🙌 {(w.supporters || []).length}人</div>
                    </div>
                    <DeleteBtn onConfirm={() => wantsCtrl.removeItem(w.id)}/>
                  </div>

                  {/* ギフト会計管理 */}
                  {(w.gifts || []).length > 0 && (
                    <div style={s.giftAdminBox}>
                      <div style={s.giftAdminLabel}>🎁 受け取った応援ギフト</div>
                      {(w.gifts || []).map(g => (
                        <div key={g.giftEntryId} style={s.giftAdminRow}>
                          <span style={{ fontSize: '1.125rem' }}>{g.emoji || '🎁'}</span>
                          <div style={{ flex: 1, minWidth: 0 }}>
                            <div style={{ fontFamily: FONT_HAND, fontSize: '0.75rem', fontWeight: 700, color: C.ink }}>{g.giftName}</div>
                            <div style={{ fontFamily: FONT_HAND, fontSize: '0.625rem', color: C.inkSub }}>
                              from {g.sender}・{new Date(g.at).toLocaleString('ja-JP', { month: 'numeric', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
                            </div>
                          </div>
                          <button
                            onClick={() => {
                              wantsCtrl.updateItem(w.id, (cur) => ({
                                ...cur,
                                gifts: (cur.gifts || []).map(x =>
                                  x.giftEntryId === g.giftEntryId ? { ...x, paid: !x.paid } : x
                                )
                              }));
                            }}
                            style={{
                              ...s.payToggleBtn,
                              background: g.paid ? C.green : C.yellow,
                              color: '#fff'
                            }}
                          >
                            {g.paid ? '✓ お会計済' : '○ お会計する'}
                          </button>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {sub === 'cityHopes' && (
        <div>
          {cityHopes.length === 0 ? (
            <div style={s.adminEmpty}>投稿がありません</div>
          ) : (
            <div style={s.adminCardList}>
              {cityHopes.map(c => (
                <div key={c.id} style={s.adminCard}>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={s.adminCardTitle}>{c.hope}</div>
                    <div style={s.adminCardMeta}>📍 {c.regionLabel}・by {c.penname}・💗 {(c.empathy || []).length}人</div>
                  </div>
                  <DeleteBtn onConfirm={() => cityHopesCtrl.removeItem(c.id)}/>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

