function GiftEditModal({ gift, isNew, onSave, onCancel }) {
  const [form, setForm] = useState(gift || { id: '', name: '', description: '', emoji: '🍺', color: '#F39C12', photo: null });

  const save = () => {
    if (!form.name.trim()) {
      alert('商品名は必須です');
      return;
    }
    onSave({
      ...form,
      id: form.id || `gift_${Date.now()}`,
      name: form.name.trim().slice(0, 40),
      description: form.description.trim().slice(0, 60),
      emoji: form.emoji || '🎁'
    });
  };

  return (
    <div style={s.modalOverlay} onClick={onCancel}>
      <div style={s.modal} onClick={(e) => e.stopPropagation()}>
        <h3 style={{ fontFamily: FONT_DISPLAY, fontSize: '1.375rem', fontWeight: 700, margin: '0 0 8px', letterSpacing: 4 }}>{isNew ? '商品を追加' : '商品を編集'}</h3>
        <AccentLine height={2} style={{ marginBottom: 20, width: 60 }} />

        <div style={s.field}>
          <label style={s.modalLabel}>商品名</label>
          <input type="text" value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} placeholder="例：日々一泡 ペールエール" style={s.input} maxLength={40}/>
        </div>

        <div style={s.field}>
          <label style={s.modalLabel}>説明</label>
          <input type="text" value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} placeholder="例：すっきりした飲み口" style={s.input} maxLength={60}/>
        </div>

        <div style={s.field}>
          <label style={s.modalLabel}>写真</label>
          {form.photo ? (
            <div style={s.photoPreview}>
              <img src={form.photo} alt="" style={{ ...s.photoPreviewImg, maxHeight: 180 }}/>
              <button type="button" onClick={() => setForm({ ...form, photo: null })} style={s.photoRemoveBtn}>✕ 削除</button>
            </div>
          ) : (
            <label style={s.photoUploadBox}>
              <input type="file" accept="image/*" onChange={(e) => {
                const file = e.target.files?.[0];
                if (file) resizeImageFile(file, (data) => setForm(f => ({ ...f, photo: data })));
              }} style={{ display: 'none' }}/>
              <div style={{ fontSize: '1.75rem', marginBottom: 6 }}>📷</div>
              <div style={{ fontFamily: FONT_HAND, fontSize: '0.75rem', fontWeight: 600, color: C.ink }}>商品写真を選ぶ</div>
            </label>
          )}
        </div>

        <div style={s.field}>
          <label style={s.modalLabel}>アイコン絵文字（写真なしの時に表示）</label>
          <input type="text" value={form.emoji} onChange={(e) => setForm({ ...form, emoji: e.target.value })} placeholder="🍺" style={s.input} maxLength={4}/>
        </div>

        <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 8, marginTop: 24 }}>
          <button onClick={onCancel} style={s.modalBtnGhost}>キャンセル</button>
          <button onClick={save} style={s.modalBtnPrimary}>保存</button>
        </div>
      </div>
    </div>
  );
}

