// 管理：タグタブ
// =====================================
function TagsAdminTab({ tags, addTag, updateTag, deleteTag, moveTag }) {
  const [editing, setEditing] = useState(null);
  const [adding, setAdding] = useState(false);

  const arrowBtn = (disabled, onClick, label) => (
    <button
      onClick={onClick}
      disabled={disabled}
      title={label}
      style={{
        ...s.rowBtn,
        padding: '4px 8px',
        fontSize: '0.875rem',
        opacity: disabled ? 0.25 : 1,
        cursor: disabled ? 'default' : 'pointer',
        lineHeight: 1,
      }}
    >
      {label}
    </button>
  );

  return (
    <div>
      <div style={{ display: 'flex', gap: 12, marginBottom: 16, alignItems: 'center' }}>
        <div style={{ fontFamily: FONT_HAND, fontSize: '0.8125rem', color: C.inkSub, flex: 1 }}>
          投稿時に選べるタグを管理。↑↓で表示順を変更できます。
        </div>
        <button onClick={() => setAdding(true)} style={{ ...s.btnGhost, background: C.green, color: '#fff', border: 'none' }}>＋ タグを追加</button>
      </div>

      <div style={s.tagAdminGrid}>
        {tags.map((t, i) => (
          <div key={t.key} style={{ ...s.tagAdminCard, borderLeft: `4px solid ${t.color}` }}>
            <div style={{ display: 'flex', gap: 10, alignItems: 'center', marginBottom: 10 }}>
              <span style={{ fontSize: '1.75rem' }}>{t.emoji}</span>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontFamily: FONT_DISPLAY, fontSize: '0.9375rem', fontWeight: 700, letterSpacing: 1 }}>{t.label}</div>
                <div style={{ fontFamily: FONT_LATIN, fontSize: '0.625rem', color: C.inkSub, marginTop: 2 }}>{t.key}</div>
              </div>
              <span style={{ width: 18, height: 18, borderRadius: 4, background: t.color, border: `1px solid ${C.line}` }}/>
            </div>
            <div style={{ display: 'flex', gap: 6, alignItems: 'center' }}>
              {arrowBtn(i === 0,              () => moveTag(t.key, -1), '↑')}
              {arrowBtn(i === tags.length - 1, () => moveTag(t.key, +1), '↓')}
              <button onClick={() => setEditing({ ...t })} style={s.rowBtn}>編集</button>
              <DeleteBtn onConfirm={() => deleteTag(t.key)}/>
            </div>
          </div>
        ))}
      </div>

      {(editing || adding) && (
        <TagEditModal
          tag={editing}
          isNew={adding}
          existingKeys={tags.map(t => t.key)}
          onSave={(t) => {
            if (adding) addTag(t);
            else updateTag(editing.key, t);
            setEditing(null);
            setAdding(false);
          }}
          onCancel={() => { setEditing(null); setAdding(false); }}
        />
      )}
    </div>
  );
}

function TagEditModal({ tag, isNew, existingKeys, onSave, onCancel }) {
  const [form, setForm] = useState(tag || { key: '', label: '', emoji: '📍', color: '#3498DB' });

  const save = () => {
    if (!form.label.trim()) { alert('タグ名は必須です'); return; }
    let key = form.key.trim();
    if (isNew) {
      // 新規時はキーを自動生成（タイムスタンプ + ランダム）
      if (!key) key = `tag_${Date.now().toString(36)}${Math.random().toString(36).slice(2, 4)}`;
      if (existingKeys.includes(key)) { alert('そのキーは既に使われています'); return; }
    }
    onSave({
      key,
      label: form.label.trim().slice(0, 20),
      emoji: form.emoji.trim() || '📍',
      color: form.color || '#3498DB'
    });
  };

  const PRESETS = ['#E6007E', '#19A86B', '#F39C12', '#3498DB', '#9B59B6', '#1ABC9C', '#E74C3C', '#E67E22', '#16A085', '#8E44AD', '#2E8B57', '#F1C40F', '#C0392B', '#A569BD', '#34495E', '#7F8C8D'];

  return (
    <div style={s.modalOverlay} onClick={onCancel}>
      <div style={s.modal} onClick={(e) => e.stopPropagation()}>
        <h3 style={{ fontFamily: FONT_DISPLAY, fontSize: '1.375rem', fontWeight: 700, margin: '0 0 8px', letterSpacing: 4 }}>{isNew ? 'タグを追加' : 'タグを編集'}</h3>
        <AccentLine height={2} style={{ marginBottom: 20, width: 60 }} />

        {/* プレビュー */}
        <div style={{ textAlign: 'center', marginBottom: 16 }}>
          <span style={{ ...s.tagPickBtn, background: form.color, color: '#fff', borderColor: form.color, fontSize: '0.875rem' }}>
            {form.emoji} {form.label || 'タグ名'}
          </span>
        </div>

        <div style={s.field}>
          <label style={s.modalLabel}>タグ名</label>
          <input type="text" value={form.label} onChange={(e) => setForm({ ...form, label: e.target.value })} placeholder="例：グルメ" style={s.input} maxLength={20}/>
        </div>

        <div style={s.field}>
          <label style={s.modalLabel}>アイコン絵文字</label>
          <input type="text" value={form.emoji} onChange={(e) => setForm({ ...form, emoji: e.target.value })} placeholder="🍴" style={s.input} maxLength={4}/>
        </div>

        <div style={s.field}>
          <label style={s.modalLabel}>色</label>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6, marginBottom: 8 }}>
            {PRESETS.map(c => (
              <button key={c} type="button" onClick={() => setForm({ ...form, color: c })}
                style={{
                  width: 32, height: 32, borderRadius: 6, background: c,
                  border: form.color === c ? `3px solid ${C.ink}` : `1px solid ${C.line}`,
                  cursor: 'pointer'
                }}/>
            ))}
          </div>
          <input type="text" value={form.color} onChange={(e) => setForm({ ...form, color: e.target.value })} placeholder="#3498DB" style={s.input}/>
        </div>

        <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 8, marginTop: 24 }}>
          <button onClick={onCancel} style={s.modalBtnGhost}>キャンセル</button>
          <button onClick={save} style={s.modalBtnPrimary}>保存</button>
        </div>
      </div>
    </div>
  );
}

function PostsTab({ posts, removePost, removeAllPosts, updatePost, stores }) {
  const [filter, setFilter] = useState('');
  const [confirmId, setConfirmId] = useState(null);
  const [confirmAll, setConfirmAll] = useState(false);
  const [editingPost, setEditingPost] = useState(null);
  const [editForm, setEditForm] = useState({});
  const editPhotoInputRef = useRef(null);
  const filtered = filter ? posts.filter(p => (p.message + p.penname + (p.prefectureName||'')).includes(filter)) : posts;

  // datetime-local 変換ヘルパー
  const toDatetimeLocal = (ms) => {
    const d = new Date(ms);
    const pad = n => String(n).padStart(2, '0');
    return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
  };

  const startEdit = (post) => {
    setEditingPost(post.id);
    setEditForm({
      penname:    post.penname    || '',
      message:    post.message    || '',
      prefecture: post.prefecture || '',
      storeId:    post.storeId    || '',
      ageGroup:   post.ageGroup   || '',
      gender:     post.gender     || '',
      photos:     post.photos || (post.photo ? [post.photo] : []),
      timestamp:  post.timestamp  || Date.now(),
    });
  };

  const saveEdit = () => {
    if (!editingPost) return;
    updatePost(editingPost, p => {
      const pref  = PREFS[editForm.prefecture];
      const store = editForm.storeId ? stores[editForm.storeId] : null;
      return {
        ...p,
        penname:       editForm.penname,
        message:       editForm.message,
        prefecture:    editForm.prefecture || p.prefecture,
        prefectureName: pref ? pref.name : p.prefectureName,
        region:        store ? store.name : (pref ? pref.region : p.region),
        storeId:       editForm.storeId || null,
        storeName:     store ? store.name : null,
        ageGroup:      editForm.ageGroup  || null,
        gender:        editForm.gender    || null,
        photos:        editForm.photos.length > 0 ? editForm.photos : null,
        photo:         editForm.photos[0] || null,
        timestamp:     editForm.timestamp,
      };
    });
    setEditingPost(null);
  };

  // 編集中の都道府県に紐づくお店一覧
  const editableStores = useMemo(() =>
    Object.values(stores).filter(st => st.parentPref === editForm.prefecture),
    [stores, editForm.prefecture]
  );

  const downloadCSV = () => {
    const header = 'ID,ペンネーム,メッセージ,地域,お店,詳細,タグ,年齢層,性別,写真,日時\n';
    const rows = posts.map(p => {
      const date = new Date(p.timestamp).toLocaleString('ja-JP');
      const esc = (x) => `"${String(x || '').replace(/"/g, '""')}"`;
      const tagStr = (p.tags || []).join('|');
      return [p.id, p.penname, p.message, p.prefectureName, p.storeName || '', p.detail?.name || '', tagStr, p.ageGroup || '', p.gender || '', p.photo ? 'あり' : '', date].map(esc).join(',');
    }).join('\n');
    const blob = new Blob(['\uFEFF' + header + rows], { type: 'text/csv;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `posts_${Date.now()}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div>
      <div style={{ display: 'flex', gap: 12, marginBottom: 16, flexWrap: 'wrap' }}>
        <input type="text" value={filter} onChange={(e) => setFilter(e.target.value)} placeholder="🔍 検索" style={s.adminSearch}/>
        <button onClick={downloadCSV} style={s.btnGhost} disabled={posts.length === 0}>↓ CSV</button>
        {!confirmAll ? (
          <button onClick={() => setConfirmAll(true)} style={s.btnDanger} disabled={posts.length === 0}>全削除</button>
        ) : (
          <div style={{ display: 'flex', gap: 6, alignItems: 'center', background: C.pinkLight, padding: '6px 10px', borderRadius: 6 }}>
            <span style={{ fontSize: '0.75rem', fontWeight: 700, color: C.pink, fontFamily: FONT_HAND }}>全{posts.length}件 削除しますか？</span>
            <button onClick={() => { removeAllPosts(); setConfirmAll(false); }} style={{ ...s.btnDanger, padding: '4px 12px' }}>はい</button>
            <button onClick={() => setConfirmAll(false)} style={{ ...s.btnGhost, padding: '4px 12px' }}>やめる</button>
          </div>
        )}
      </div>

      {filtered.length === 0 ? (
        <div style={{ textAlign: 'center', padding: 60, fontFamily: FONT_HAND, color: C.inkLight }}>投稿がありません</div>
      ) : (
        <div style={s.adminTable}>
          <div style={s.adminTableHead}>
            <div style={{ flex: '0 0 50px' }}>📷</div>
            <div style={{ flex: '0 0 90px' }}>地域</div>
            <div style={{ flex: '0 0 110px' }}>ペンネーム</div>
            <div style={{ flex: 1 }}>メッセージ</div>
            <div style={{ flex: '0 0 110px' }}>属性</div>
            <div style={{ flex: '0 0 90px' }}>日時</div>
            <div style={{ flex: '0 0 90px' }}>操作</div>
          </div>
          {filtered.map(post => (
            <div key={post.id} style={s.adminRow}>
              <div style={{ flex: '0 0 50px' }}>
                {post.photo ? (
                  <img src={post.photo} alt="" style={{ width: 40, height: 40, objectFit: 'cover', borderRadius: 3, border: `1px solid ${C.line}` }}/>
                ) : (
                  <span style={{ color: C.inkLight, fontSize: '0.6875rem' }}>—</span>
                )}
              </div>
              <div style={{ flex: '0 0 90px', fontFamily: FONT_HAND, fontSize: '0.75rem' }}>{post.storeName ? `🏠 ${post.storeName}` : post.prefectureName}</div>
              <div style={{ flex: '0 0 110px', fontFamily: FONT_HAND, fontSize: '0.8125rem' }}>{post.penname}</div>
              <div style={{ flex: 1, fontSize: '0.8125rem', lineHeight: 1.5 }}>{post.message}</div>
              <div style={{ flex: '0 0 110px', fontSize: '0.625rem', color: C.inkSub, display: 'flex', flexDirection: 'column', gap: 2 }}>
                {post.ageGroup && <span style={{ fontWeight: 600 }}>{post.ageGroup}</span>}
                {post.gender && <span>{post.gender}</span>}
                {!post.ageGroup && !post.gender && <span style={{ color: C.inkLight }}>—</span>}
              </div>
              <div style={{ flex: '0 0 90px', fontSize: '0.6875rem', color: C.inkSub }}>
                {new Date(post.timestamp).toLocaleString('ja-JP', { month: 'numeric', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
              </div>
              <div style={{ flex: '0 0 90px', display: 'flex', gap: 4, flexWrap: 'wrap' }}>
                {confirmId === post.id ? (
                  <>
                    <button onClick={() => { removePost(post.id); setConfirmId(null); }} style={{ ...s.rowBtn, background: C.pink, color: '#fff', borderColor: C.pink, padding: '3px 6px', fontSize: '0.6875rem' }}>確定</button>
                    <button onClick={() => setConfirmId(null)} style={{ ...s.rowBtn, padding: '3px 6px', fontSize: '0.6875rem' }}>×</button>
                  </>
                ) : (
                  <>
                    <button onClick={() => startEdit(post)} style={{ ...s.rowBtn, color: C.green, borderColor: C.green, padding: '3px 6px', fontSize: '0.6875rem' }}>編集</button>
                    <button onClick={() => setConfirmId(post.id)} style={{ ...s.rowBtn, color: C.pink, borderColor: C.pink, padding: '3px 6px', fontSize: '0.6875rem' }}>削除</button>
                  </>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* 編集モーダル */}
      {editingPost && (() => {
        const fld = (label, children) => (
          <div style={{ marginBottom: 14 }}>
            <label style={{ fontSize: '0.6875rem', color: C.inkSub, fontFamily: FONT_HAND, display: 'block', marginBottom: 4, fontWeight: 700 }}>{label}</label>
            {children}
          </div>
        );
        const inp = { ...s.adminSearch, width: '100%', marginBottom: 0, boxSizing: 'border-box' };
        const sel = { ...inp };
        return (
          <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 200, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 16, overflowY: 'auto' }}>
            <div style={{ background: C.bgWhite, borderRadius: 12, padding: 24, width: '100%', maxWidth: 600, boxShadow: '0 8px 32px rgba(0,0,0,0.25)', maxHeight: '90vh', overflowY: 'auto' }}>

              <div style={{ fontFamily: FONT_DISPLAY, fontSize: '1rem', fontWeight: 700, letterSpacing: 2, marginBottom: 20 }}>投稿を編集</div>

              {/* ペンネーム */}
              {fld('ペンネーム',
                <input value={editForm.penname} onChange={e => setEditForm(f => ({ ...f, penname: e.target.value }))} style={inp}/>
              )}

              {/* メッセージ */}
              {fld('メッセージ',
                <textarea value={editForm.message} onChange={e => setEditForm(f => ({ ...f, message: e.target.value }))}
                  rows={3} style={{ ...inp, resize: 'vertical', fontFamily: FONT_BODY, lineHeight: 1.6 }}/>
              )}

              {/* 地域（都道府県） */}
              {fld('地域',
                <select value={editForm.prefecture} onChange={e => setEditForm(f => ({ ...f, prefecture: e.target.value, storeId: '' }))} style={sel}>
                  <option value="">選択してください</option>
                  {REGION_GROUPS.map(r => {
                    const prefs = Object.entries(PREFS).filter(([k, p]) => p.region === r && k !== 'overseas');
                    if (!prefs.length) return null;
                    return (
                      <optgroup key={r} label={r}>
                        {prefs.map(([k, p]) => <option key={k} value={k}>{p.name}</option>)}
                      </optgroup>
                    );
                  })}
                  <option value="overseas">🌍 海外</option>
                </select>
              )}

              {/* お店（地域選択後に表示） */}
              {editableStores.length > 0 && fld('お店（任意）',
                <select value={editForm.storeId} onChange={e => setEditForm(f => ({ ...f, storeId: e.target.value }))} style={sel}>
                  <option value="">お店なし</option>
                  {editableStores.map(st => <option key={st.id} value={st.id}>{st.name}</option>)}
                </select>
              )}

              {/* 年齢層 */}
              {fld('年齢層',
                <select value={editForm.ageGroup} onChange={e => setEditForm(f => ({ ...f, ageGroup: e.target.value }))} style={{ ...sel }}>
                  <option value="">未設定</option>
                  {AGE_OPTIONS.map(a => <option key={a} value={a}>{a}</option>)}
                </select>
              )}

              {/* 属性 */}
              {fld('属性',
                <select value={editForm.gender} onChange={e => setEditForm(f => ({ ...f, gender: e.target.value }))} style={{ ...sel }}>
                  <option value="">未設定</option>
                  {GENDER_OPTIONS.map(g => <option key={g} value={g}>{g}</option>)}
                </select>
              )}

              {/* 日時 */}
              {fld('日時',
                <input type="datetime-local" value={toDatetimeLocal(editForm.timestamp)}
                  onChange={e => setEditForm(f => ({ ...f, timestamp: new Date(e.target.value).getTime() }))}
                  style={{ ...inp }}/>
              )}

              {/* 写真 */}
              {fld('写真',
                <div>
                  {editForm.photos && editForm.photos.length > 0 && (
                    <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', marginBottom: 8 }}>
                      {editForm.photos.map((ph, i) => (
                        <div key={i} style={{ position: 'relative', width: 72, height: 72 }}>
                          <img src={ph} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover', borderRadius: 6, border: `1px solid ${C.line}` }}/>
                          <button onClick={() => setEditForm(f => ({ ...f, photos: f.photos.filter((_, j) => j !== i) }))}
                            style={{ position: 'absolute', top: 2, right: 2, width: 20, height: 20, borderRadius: '50%', background: 'rgba(0,0,0,0.7)', color: '#fff', border: 'none', cursor: 'pointer', fontSize: '0.6875rem', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 0 }}>
                            ✕
                          </button>
                        </div>
                      ))}
                    </div>
                  )}
                  <input ref={editPhotoInputRef} type="file" accept="image/*" multiple style={{ display: 'none' }}
                    onChange={e => {
                      Array.from(e.target.files).forEach(file => {
                        resizeImageFile(file, data => setEditForm(f => ({ ...f, photos: [...(f.photos || []), data] })));
                      });
                      e.target.value = '';
                    }}
                  />
                  <button onClick={() => editPhotoInputRef.current?.click()}
                    style={{ ...s.btnGhost, fontSize: '0.75rem', padding: '4px 12px' }}>
                    ＋ 写真を追加
                  </button>
                </div>
              )}

              <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 4 }}>
                <button onClick={() => setEditingPost(null)} style={s.btnGhost}>キャンセル</button>
                <button onClick={saveEdit} style={{ ...s.btnGhost, background: C.green, color: '#fff', borderColor: C.green }}>保存</button>
              </div>
            </div>
          </div>
        );
      })()}
    </div>
  );
}

function StoresTab({ stores, saveStore, deleteStore }) {
  const [editing, setEditing] = useState(null);
  const [adding, setAdding] = useState(false);

  return (
    <div>
      <div style={{ display: 'flex', gap: 12, marginBottom: 16, alignItems: 'center' }}>
        <div style={{ fontFamily: FONT_HAND, fontSize: '0.8125rem', color: C.inkSub, flex: 1 }}>
          街中スナックのお店を管理。マップに🏠アイコンで表示されます。
        </div>
        <button onClick={() => setAdding(true)} style={{ ...s.btnGhost, background: C.green, color: '#fff', border: 'none' }}>＋ お店を追加</button>
      </div>

      <div style={s.storeGrid}>
        {Object.values(stores).map(store => (
          <div key={store.id} style={s.storeCard}>
            <div style={{ display: 'flex', gap: 12, marginBottom: 12 }}>
              <div style={{ fontSize: '2rem' }}>🏠</div>
              <div style={{ flex: 1 }}>
                <div style={{ fontFamily: FONT_DISPLAY, fontSize: '1.125rem', fontWeight: 700, letterSpacing: 2 }}>{store.name}</div>
                <div style={{ fontFamily: FONT_HAND, fontSize: '0.75rem', color: C.inkSub, marginTop: 2 }}>{store.fullName}</div>
              </div>
            </div>
            <div style={{ fontFamily: FONT_HAND, fontSize: '0.75rem', color: C.inkSub, lineHeight: 1.8, padding: '8px 0', borderTop: '1px dashed ' + C.line, borderBottom: '1px dashed ' + C.line, marginBottom: 12 }}>
              <div><strong>所在地：</strong>{PREFS[store.parentPref]?.name || store.parentPref}</div>
              <div><strong>説明：</strong>{store.description}</div>
            </div>
            <div style={{ display: 'flex', gap: 6 }}>
              <button onClick={() => setEditing({ ...store })} style={s.rowBtn}>編集</button>
              <DeleteBtn onConfirm={() => deleteStore(store.id)}/>
            </div>
          </div>
        ))}
      </div>

      {(editing || adding) && (
        <StoreModal
          store={editing}
          isNew={adding}
          onSave={(store) => { saveStore(store); setEditing(null); setAdding(false); }}
          onCancel={() => { setEditing(null); setAdding(false); }}
        />
      )}
    </div>
  );
}

function StoreModal({ store, isNew, onSave, onCancel }) {
  const [form, setForm] = useState(store || { id: '', name: '', fullName: '', parentPref: '', x: 625, y: 435, description: '' });

  const save = () => {
    if (!form.name.trim() || !form.parentPref) {
      alert('お店の名前と所在地は必須です');
      return;
    }
    const pref = PREFS[form.parentPref];
    const final = {
      ...form,
      id: form.id || `store_${Date.now()}`,
      name: form.name.trim().slice(0, 20),
      fullName: form.fullName.trim().slice(0, 50),
      description: form.description.trim().slice(0, 60),
      x: pref?.x || 625,
      y: pref?.y || 435
    };
    onSave(final);
  };

  return (
    <div style={s.modalOverlay} onClick={onCancel}>
      <div style={s.modal} onClick={(e) => e.stopPropagation()}>
        <h3 style={{ fontFamily: FONT_DISPLAY, fontSize: '1.375rem', fontWeight: 700, margin: '0 0 8px', letterSpacing: 4 }}>{isNew ? 'お店を追加' : 'お店を編集'}</h3>
        <AccentLine height={2} style={{ marginBottom: 20, width: 60 }} />

        <div style={s.field}>
          <label style={s.modalLabel}>お店の名前（短く）</label>
          <input type="text" value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} placeholder="例：荒川区" style={s.input} maxLength={20}/>
        </div>

        <div style={s.field}>
          <label style={s.modalLabel}>正式名</label>
          <input type="text" value={form.fullName} onChange={(e) => setForm({ ...form, fullName: e.target.value })} placeholder="例：ARAKAWA LABO 本店" style={s.input} maxLength={50}/>
        </div>

        <div style={s.field}>
          <label style={s.modalLabel}>所在地（都道府県）</label>
          <select value={form.parentPref} onChange={(e) => setForm({ ...form, parentPref: e.target.value })} style={s.select}>
            <option value="">— 選択 —</option>
            {Object.entries(PREFS).filter(([k]) => k !== 'overseas').map(([key, pref]) => (
              <option key={key} value={key}>{pref.name}</option>
            ))}
          </select>
        </div>

        <div style={s.field}>
          <label style={s.modalLabel}>説明</label>
          <input type="text" value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} placeholder="例：街中スナック ARAKAWA LABO 本店" style={s.input} maxLength={60}/>
        </div>

        <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 8, marginTop: 24 }}>
          <button onClick={onCancel} style={s.modalBtnGhost}>キャンセル</button>
          <button onClick={save} style={s.modalBtnPrimary}>保存</button>
        </div>
      </div>
    </div>
  );
}

