function BoardScreen({ events, eventsCtrl, wants, wantsCtrl, cityHopes, cityHopesCtrl, gifts, stores, settings }) {
  const [mode, setMode] = useState(null); // null=トップ, 'events', 'wants', 'cityHopes'

  const features = [
    {
      key: 'events',
      show: settings.showEvents,
      icon: '📣',
      color: C.green,
      title: 'ゆるく募集する',
      desc: 'イベントや集まりを企画して、参加者を募ろう',
      count: events.length
    },
    {
      key: 'wants',
      show: settings.showWants,
      icon: '✨',
      color: C.yellow,
      title: 'やってみたい！',
      desc: 'やりたいことを宣言。応援＆ギフトを送り合おう',
      count: wants.length
    },
    {
      key: 'cityHopes',
      show: settings.showCityHopes,
      icon: '🌸',
      color: C.pink,
      title: 'こんな街になったらいいな',
      desc: '街への思いをシェア。共感を集めよう',
      count: cityHopes.length
    }
  ].filter(f => f.show);

  // 各機能画面
  if (mode === 'events') {
    return <EventsBoard events={events} ctrl={eventsCtrl} stores={stores} onBack={() => setMode(null)}/>;
  }
  if (mode === 'wants') {
    return <WantsBoard wants={wants} ctrl={wantsCtrl} gifts={gifts} onBack={() => setMode(null)}/>;
  }
  if (mode === 'cityHopes') {
    return <CityHopesBoard cityHopes={cityHopes} ctrl={cityHopesCtrl} onBack={() => setMode(null)}/>;
  }

  // トップ画面
  return (
    <div style={s.boardScreen}>
      <div style={s.boardContainer}>
        <header style={{ textAlign: 'center', marginBottom: 32 }}>
          <div style={s.boardKanji}>街中</div>
          <h1 style={s.boardTitle}>掲示板</h1>
          <p style={s.boardSubtitle}>みんなで作る、街の交流ボード</p>
          <AccentLine style={{ width: 80, margin: '20px auto 0' }} />
        </header>

        {features.length === 0 ? (
          <div style={{ textAlign: 'center', padding: 60, fontFamily: FONT_HAND, color: C.inkLight }}>
            現在、掲示板機能はすべて非表示です
          </div>
        ) : (
          <div style={s.featureGrid}>
            {features.map(f => (
              <button key={f.key} onClick={() => setMode(f.key)} style={{ ...s.featureCard, borderTopColor: f.color }}>
                <div style={{ ...s.featureIcon, background: f.color + '20' }}>{f.icon}</div>
                <div style={s.featureBody}>
                  <div style={s.featureTitle}>{f.title}</div>
                  <div style={s.featureDesc}>{f.desc}</div>
                </div>
                <div style={{ ...s.featureCount, color: f.color }}>
                  {f.count}<span style={{ fontSize: '0.6875rem', marginLeft: 2 }}>件</span>
                </div>
                <div style={{ ...s.featureArrow, color: f.color }}>→</div>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

// =====================================
// 【1】ゆるく募集する（イベント企画）
// =====================================
function EventsBoard({ events, ctrl, stores, onBack }) {
  const [creating, setCreating] = useState(false);
  const [detailId, setDetailId] = useState(null);

  if (creating) {
    return <EventCreate stores={stores} onSubmit={(ev) => { ctrl.addItem(ev); setCreating(false); }} onCancel={() => setCreating(false)}/>;
  }
  if (detailId) {
    const ev = events.find(e => e.id === detailId);
    if (!ev) { setDetailId(null); return null; }
    return <EventDetail event={ev} ctrl={ctrl} onBack={() => setDetailId(null)}/>;
  }

  return (
    <div style={s.boardScreen}>
      <div style={s.boardContainer}>
        <button onClick={onBack} style={s.backBtn}>← 掲示板トップ</button>
        <header style={{ textAlign: 'center', marginBottom: 24 }}>
          <div style={{ fontSize: '2.5rem' }}>📣</div>
          <h1 style={{ ...s.boardTitle, fontSize: '1.5rem' }}>ゆるく募集する</h1>
          <p style={s.boardSubtitle}>イベントや集まりを企画しよう</p>
          <AccentLine style={{ width: 60, margin: '16px auto 0' }} />
        </header>

        <button onClick={() => setCreating(true)} style={{ ...s.bigActionBtn, background: C.green, boxShadow: `0 3px 0 ${C.greenDark}` }}>
          <span style={s.bigActionIcon}>＋</span>
          <span>募集をはじめる</span>
        </button>

        {events.length === 0 ? (
          <div style={s.boardEmpty}>
            <div style={{ fontSize: '3rem' }}>🗓️</div>
            <div style={s.boardEmptyTitle}>まだ募集がありません</div>
            <div style={s.boardEmptySub}>最初のイベントを企画してみよう</div>
          </div>
        ) : (
          <div style={s.cardList}>
            {events.map((ev, idx) => {
              const color = [C.green, C.yellow, C.pink][idx % 3];
              const date = new Date(ev.datetime);
              const dateStr = `${date.getMonth() + 1}/${date.getDate()}`;
              const dow = ['日','月','火','水','木','金','土'][date.getDay()];
              const timeStr = `${String(date.getHours()).padStart(2,'0')}:${String(date.getMinutes()).padStart(2,'0')}`;
              const pastEvent = date.getTime() < Date.now() - 86400000;
              return (
                <button key={ev.id} onClick={() => setDetailId(ev.id)} style={{ ...s.eventCard, borderLeftColor: color, opacity: pastEvent ? 0.55 : 1 }}>
                  <div style={s.eventCardDate}>
                    <div style={{ ...s.eventCardDateNum, color }}>{dateStr}</div>
                    <div style={s.eventCardDow}>({dow})</div>
                    <div style={s.eventCardTime}>{timeStr}〜</div>
                  </div>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    {ev.photo && <img src={ev.photo} alt="" style={s.cardThumb}/>}
                    <div style={s.eventCardTitle}>{ev.title}</div>
                    <div style={s.eventCardPlace}>📍 {ev.place}</div>
                    <div style={s.eventCardMeta}>
                      <span>主催: {ev.host}</span>
                      <span style={{ ...s.joinPill, background: color + '20', color }}>
                        👥 {(ev.participants || []).length}人
                      </span>
                    </div>
                  </div>
                </button>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

function EventCreate({ stores, onSubmit, onCancel }) {
  const [title, setTitle] = useState('');
  const [host, setHost] = useState('');
  const [date, setDate] = useState('');
  const [time, setTime] = useState('19:00');
  const [placeType, setPlaceType] = useState('');  // store id or 'other'
  const [otherPlace, setOtherPlace] = useState('');
  const [description, setDescription] = useState('');
  const [photo, setPhoto] = useState(null);
  const [ageGroup, setAgeGroup] = useState('');
  const [gender, setGender] = useState('');
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('mn_penname');
    if (saved) setHost(saved);
    const t = new Date();
    t.setDate(t.getDate() + 1);
    setDate(t.toISOString().slice(0, 10));
  }, []);

  const place = placeType === 'other' ? otherPlace.trim() : (stores[placeType]?.fullName || '');
  const canSubmit = title.trim() && host.trim() && date && time && place && !submitting;

  const handleSubmit = () => {
    if (!canSubmit) return;
    setSubmitting(true);
    try { localStorage.setItem('mn_penname', host); } catch {}
    onSubmit({
      id: `event_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
      title: title.trim().slice(0, 60),
      host: host.trim().slice(0, 20),
      datetime: `${date}T${time}:00`,
      place: place.slice(0, 60),
      description: description.trim().slice(0, 280),
      photo: photo || null,
      ageGroup: ageGroup || null,
      gender: gender || null,
      participants: [],
      timestamp: Date.now()
    });
  };

  return (
    <div style={s.boardScreen}>
      <div style={s.boardContainer}>
        <button onClick={onCancel} style={s.backBtn}>← 戻る</button>
        <header style={{ textAlign: 'center', marginBottom: 24 }}>
          <h1 style={{ ...s.boardTitle, fontSize: '1.375rem' }}>募集をはじめる</h1>
          <AccentLine style={{ width: 60, margin: '12px auto 0' }} />
        </header>

        <div style={s.field}>
          <label style={s.label}><span style={{ ...s.labelDot, background: C.green }} />イベント名<span style={s.required}>必須</span></label>
          <input type="text" value={title} onChange={(e) => setTitle(e.target.value)} placeholder="例：スポーツ好き集まれ！観戦ナイト" maxLength={60} style={s.input}/>
        </div>

        <div style={s.field}>
          <label style={s.label}><span style={{ ...s.labelDot, background: C.green }} />主催者（ペンネーム）<span style={s.required}>必須</span></label>
          <input type="text" value={host} onChange={(e) => setHost(e.target.value)} placeholder="例：るいさん" maxLength={20} style={s.input}/>
        </div>

        <div style={s.field}>
          <label style={s.label}><span style={{ ...s.labelDot, background: C.yellow }} />日時<span style={s.required}>必須</span></label>
          <div style={{ display: 'flex', gap: 8 }}>
            <input type="date" value={date} onChange={(e) => setDate(e.target.value)} style={{ ...s.input, flex: '1 1 60%' }}/>
            <input type="time" value={time} onChange={(e) => setTime(e.target.value)} style={{ ...s.input, flex: '1 1 35%' }}/>
          </div>
        </div>

        <div style={s.field}>
          <label style={s.label}><span style={{ ...s.labelDot, background: C.pink }} />場所<span style={s.required}>必須</span></label>
          <select value={placeType} onChange={(e) => setPlaceType(e.target.value)} style={s.select}>
            <option value="">— 選択してください —</option>
            {Object.values(stores).map(st => (
              <option key={st.id} value={st.id}>🏠 {st.fullName}</option>
            ))}
            <option value="other">その他の場所</option>
          </select>
          {placeType === 'other' && (
            <input type="text" value={otherPlace} onChange={(e) => setOtherPlace(e.target.value)} placeholder="場所を入力" maxLength={60} style={{ ...s.input, marginTop: 8 }}/>
          )}
        </div>

        <div style={s.field}>
          <label style={s.label}><span style={{ ...s.labelDot, background: C.green }} />詳細</label>
          <textarea value={description} onChange={(e) => setDescription(e.target.value)} placeholder="どんな集まり？持ち物・会費など…" maxLength={280} rows={4} style={s.textarea}/>
          <div style={s.charCount}>{description.length} / 280</div>
        </div>

        <OptionalFields photo={photo} setPhoto={setPhoto} ageGroup={ageGroup} setAgeGroup={setAgeGroup} gender={gender} setGender={setGender}/>

        <button onClick={handleSubmit} disabled={!canSubmit} style={{ ...s.submitBtn, opacity: canSubmit ? 1 : 0.45, cursor: canSubmit ? 'pointer' : 'not-allowed' }}>
          <span>{submitting ? '掲示中…' : '掲示板に貼る'}</span>
          {!submitting && <span style={{ fontSize: '1.125rem' }}>→</span>}
        </button>
      </div>
    </div>
  );
}

function EventDetail({ event, ctrl, onBack }) {
  const [joinName, setJoinName] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [done, setDone] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('mn_penname');
    if (saved) setJoinName(saved);
  }, []);

  const date = new Date(event.datetime);
  const dateStr = `${date.getFullYear()}年${date.getMonth()+1}月${date.getDate()}日`;
  const dow = ['日','月','火','水','木','金','土'][date.getDay()];
  const timeStr = `${String(date.getHours()).padStart(2,'0')}:${String(date.getMinutes()).padStart(2,'0')}`;
  const participants = event.participants || [];

  const handleJoin = () => {
    const name = joinName.trim().slice(0, 20);
    if (!name) return;
    if (participants.some(p => p.name === name)) {
      alert('すでに参加登録されています');
      return;
    }
    try { localStorage.setItem('mn_penname', name); } catch {}
    ctrl.updateItem(event.id, (cur) => ({
      ...cur,
      participants: [...(cur.participants || []), { name, joinedAt: Date.now() }]
    }));
    setShowForm(false);
    setDone(true);
    setTimeout(() => setDone(false), 3000);
  };

  const handleLeave = (name) => {
    ctrl.updateItem(event.id, (cur) => ({
      ...cur,
      participants: (cur.participants || []).filter(p => p.name !== name)
    }));
  };

  const handleDelete = () => {
    ctrl.removeItem(event.id);
    onBack();
  };

  return (
    <div style={s.boardScreen}>
      <div style={s.boardContainer}>
        <button onClick={onBack} style={s.backBtn}>← 一覧に戻る</button>

        <div style={{ ...s.detailCard, borderTopColor: C.green }}>
          {event.photo && <img src={event.photo} alt="" style={s.detailPhoto}/>}
          <div style={s.detailDateBox}>
            <div style={s.detailDate}>{dateStr}（{dow}）</div>
            <div style={{ ...s.detailTime, color: C.green }}>🕐 {timeStr}〜</div>
          </div>
          <h2 style={s.detailTitle}>{event.title}</h2>
          <div style={s.detailMetaRow}><span style={s.detailMetaLabel}>📍 場所</span><span>{event.place}</span></div>
          <div style={s.detailMetaRow}><span style={s.detailMetaLabel}>👤 主催</span><span>{event.host}</span></div>
          {(event.ageGroup || event.gender) && (
            <div style={s.detailMetaRow}>
              <span style={s.detailMetaLabel}>🏷 主催者</span>
              <span>{[event.ageGroup, event.gender].filter(Boolean).join(' / ')}</span>
            </div>
          )}
          {event.description && <div style={{ ...s.detailDesc, borderLeftColor: C.green }}>{event.description}</div>}
        </div>

        {/* 参加者 */}
        <div style={s.participantSection}>
          <div style={s.participantHead}>
            <h3 style={s.participantTitle}><span style={{ ...s.featureDot, background: C.green }}/>参加者</h3>
            <span style={{ ...s.participantCount, background: C.greenLight, color: C.greenDark }}>{participants.length}人</span>
          </div>
          {participants.length === 0 ? (
            <div style={s.participantEmpty}>まだ参加者がいません。最初の一人になろう！</div>
          ) : (
            <div style={s.chipList}>
              {participants.map((p, idx) => (
                <div key={`${p.name}_${p.joinedAt}`} style={{ ...s.chip, background: [C.greenLight, C.yellowLight, C.pinkLight][idx%3], borderColor: [C.green, C.yellow, C.pink][idx%3] }}>
                  <span>{p.name}</span>
                  <button onClick={() => handleLeave(p.name)} style={s.chipRemove}>×</button>
                </div>
              ))}
            </div>
          )}

          {!showForm && !done && (
            <button onClick={() => setShowForm(true)} style={{ ...s.joinBtn, background: C.green, boxShadow: `0 3px 0 ${C.greenDark}` }}>
              <span style={{ fontSize: '1.25rem' }}>👋</span><span>参加する</span>
            </button>
          )}
          {showForm && (
            <div style={{ ...s.joinForm, borderColor: C.green }}>
              <label style={s.joinFormLabel}>ペンネームを入力してください</label>
              <div style={{ display: 'flex', gap: 8, marginBottom: 8 }}>
                <input type="text" value={joinName} onChange={(e) => setJoinName(e.target.value)} placeholder="例：たんめぐさん" maxLength={20} style={s.input} autoFocus/>
                <button onClick={handleJoin} disabled={!joinName.trim()} style={{ ...s.joinFormBtn, background: C.green }}>参加</button>
              </div>
              <button onClick={() => setShowForm(false)} style={s.joinFormCancel}>キャンセル</button>
            </div>
          )}
          {done && (
            <div style={{ ...s.toast, background: C.greenLight }}>
              <span style={{ fontSize: '1.5rem' }}>🎉</span>
              <div><div style={s.toastTitle}>参加登録しました！</div><div style={s.toastSub}>当日お会いしましょう</div></div>
            </div>
          )}
        </div>

        <div style={{ display: 'flex', justifyContent: 'center', marginTop: 24 }}><DeleteBtn onConfirm={handleDelete} label="この募集を削除"/></div>
      </div>
    </div>
  );
}

// =====================================
// 【2】やってみたい！（応援＆ギフト）
// =====================================
function WantsBoard({ wants, ctrl, gifts, onBack }) {
  const [creating, setCreating] = useState(false);
  const [detailId, setDetailId] = useState(null);

  if (creating) {
    return <WantCreate onSubmit={(w) => { ctrl.addItem(w); setCreating(false); }} onCancel={() => setCreating(false)}/>;
  }
  if (detailId) {
    const w = wants.find(x => x.id === detailId);
    if (!w) { setDetailId(null); return null; }
    return <WantDetail want={w} ctrl={ctrl} gifts={gifts} onBack={() => setDetailId(null)}/>;
  }

  return (
    <div style={s.boardScreen}>
      <div style={s.boardContainer}>
        <button onClick={onBack} style={s.backBtn}>← 掲示板トップ</button>
        <header style={{ textAlign: 'center', marginBottom: 24 }}>
          <div style={{ fontSize: '2.5rem' }}>✨</div>
          <h1 style={{ ...s.boardTitle, fontSize: '1.5rem' }}>やってみたい！</h1>
          <p style={s.boardSubtitle}>やりたいことを宣言。みんなで応援しよう</p>
          <AccentLine style={{ width: 60, margin: '16px auto 0' }} />
        </header>

        <button onClick={() => setCreating(true)} style={{ ...s.bigActionBtn, background: C.yellow, boxShadow: '0 3px 0 #C87F0A' }}>
          <span style={s.bigActionIcon}>＋</span>
          <span>やりたいことを書く</span>
        </button>

        {wants.length === 0 ? (
          <div style={s.boardEmpty}>
            <div style={{ fontSize: '3rem' }}>🌟</div>
            <div style={s.boardEmptyTitle}>まだ投稿がありません</div>
            <div style={s.boardEmptySub}>「やってみたい！」を最初に宣言しよう</div>
          </div>
        ) : (
          <div style={s.cardList}>
            {wants.map((w, idx) => {
              const color = [C.yellow, C.pink, C.green][idx % 3];
              const supporters = w.supporters || [];
              const giftCount = (w.gifts || []).length;
              return (
                <button key={w.id} onClick={() => setDetailId(w.id)} style={{ ...s.eventCard, borderLeftColor: color }}>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    {w.photo && <img src={w.photo} alt="" style={s.cardThumb}/>}
                    <div style={s.wantRegionTag}>📍 {w.regionLabel}</div>
                    <div style={s.eventCardTitle}>{w.want}</div>
                    <div style={s.eventCardMeta}>
                      <span>by {w.penname}</span>
                      <span style={{ display: 'flex', gap: 6 }}>
                        <span style={{ ...s.joinPill, background: color + '20', color }}>🙌 {supporters.length}</span>
                        {giftCount > 0 && <span style={{ ...s.joinPill, background: C.pinkLight, color: C.pink }}>🎁 {giftCount}</span>}
                      </span>
                    </div>
                  </div>
                </button>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

// 地域選択（都道府県・海外・お店）共通
function RegionSelect({ value, onChange }) {
  const grouped = useMemo(() => {
    const g = {};
    REGION_GROUPS.forEach(r => { g[r] = []; });
    Object.entries(PREFS).forEach(([key, p]) => {
      if (key === 'overseas') return;
      if (g[p.region]) g[p.region].push({ key, ...p });
    });
    return g;
  }, []);

  return (
    <select value={value} onChange={(e) => onChange(e.target.value)} style={s.select}>
      <option value="">— 選択してください —</option>
      <optgroup label="街中スナック">
        <option value="store:arakawa">🏠 荒川区 ARAKAWA LABO 本店</option>
        <option value="store:iwanuma">🏠 岩沼店</option>
        <option value="store:mito">🏠 水戸店</option>
      </optgroup>
      {REGION_GROUPS.map(region => (
        <optgroup key={region} label={`${region}地方`}>
          {grouped[region].map(p => <option key={p.key} value={p.key}>{p.name}</option>)}
        </optgroup>
      ))}
      <optgroup label="その他">
        <option value="overseas">🌍 海外</option>
      </optgroup>
    </select>
  );
}

function regionLabelFromValue(val) {
  if (!val) return '';
  if (val.startsWith('store:')) {
    const id = val.slice(6);
    return { arakawa: '荒川区LABO', iwanuma: '岩沼店', mito: '水戸店' }[id] || 'お店';
  }
  if (val === 'overseas') return '海外';
  return PREFS[val]?.name || val;
}

function WantCreate({ onSubmit, onCancel }) {
  const [want, setWant] = useState('');
  const [penname, setPenname] = useState('');
  const [region, setRegion] = useState('');
  const [photo, setPhoto] = useState(null);
  const [ageGroup, setAgeGroup] = useState('');
  const [gender, setGender] = useState('');
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('mn_penname');
    if (saved) setPenname(saved);
  }, []);

  const canSubmit = want.trim() && penname.trim() && region && !submitting;

  const handleSubmit = () => {
    if (!canSubmit) return;
    setSubmitting(true);
    try { localStorage.setItem('mn_penname', penname); } catch {}
    onSubmit({
      id: `want_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
      want: want.trim().slice(0, 120),
      penname: penname.trim().slice(0, 20),
      region: region,
      regionLabel: regionLabelFromValue(region),
      photo: photo || null,
      ageGroup: ageGroup || null,
      gender: gender || null,
      supporters: [],
      gifts: [],
      timestamp: Date.now()
    });
  };

  return (
    <div style={s.boardScreen}>
      <div style={s.boardContainer}>
        <button onClick={onCancel} style={s.backBtn}>← 戻る</button>
        <header style={{ textAlign: 'center', marginBottom: 24 }}>
          <h1 style={{ ...s.boardTitle, fontSize: '1.375rem' }}>やってみたいことを書く</h1>
          <AccentLine style={{ width: 60, margin: '12px auto 0' }} />
        </header>

        <div style={s.field}>
          <label style={s.label}><span style={{ ...s.labelDot, background: C.yellow }} />やってみたいこと<span style={s.required}>必須</span></label>
          <textarea value={want} onChange={(e) => setWant(e.target.value)} placeholder="例：街中スナックでDJイベントをやってみたい！" maxLength={120} rows={3} style={s.textarea}/>
          <div style={s.charCount}>{want.length} / 120</div>
        </div>

        <div style={s.field}>
          <label style={s.label}><span style={{ ...s.labelDot, background: C.green }} />ペンネーム<span style={s.required}>必須</span></label>
          <input type="text" value={penname} onChange={(e) => setPenname(e.target.value)} placeholder="例：りささん" maxLength={20} style={s.input}/>
        </div>

        <div style={s.field}>
          <label style={s.label}><span style={{ ...s.labelDot, background: C.pink }} />地域<span style={s.required}>必須</span></label>
          <RegionSelect value={region} onChange={setRegion}/>
        </div>

        <OptionalFields photo={photo} setPhoto={setPhoto} ageGroup={ageGroup} setAgeGroup={setAgeGroup} gender={gender} setGender={setGender}/>

        <button onClick={handleSubmit} disabled={!canSubmit} style={{ ...s.submitBtn, background: C.yellow, boxShadow: '0 3px 0 #C87F0A', opacity: canSubmit ? 1 : 0.45, cursor: canSubmit ? 'pointer' : 'not-allowed' }}>
          <span>{submitting ? '掲示中…' : '掲示板に貼る'}</span>
          {!submitting && <span style={{ fontSize: '1.125rem' }}>→</span>}
        </button>
      </div>
    </div>
  );
}

function WantDetail({ want, ctrl, gifts, onBack }) {
  const [supName, setSupName] = useState('');
  const [showSupForm, setShowSupForm] = useState(false);
  const [showGiftForm, setShowGiftForm] = useState(false);
  const [giftSender, setGiftSender] = useState('');
  const [selectedGift, setSelectedGift] = useState('');
  const [done, setDone] = useState('');

  useEffect(() => {
    const saved = localStorage.getItem('mn_penname');
    if (saved) { setSupName(saved); setGiftSender(saved); }
  }, []);

  const supporters = want.supporters || [];
  const sentGifts = want.gifts || [];
  const giftList = Object.values(gifts);

  const handleSupport = () => {
    const name = supName.trim().slice(0, 20);
    if (!name) return;
    if (supporters.some(s => s.name === name)) { alert('すでに応援済みです'); return; }
    try { localStorage.setItem('mn_penname', name); } catch {}
    ctrl.updateItem(want.id, (cur) => ({
      ...cur, supporters: [...(cur.supporters || []), { name, at: Date.now() }]
    }));
    setShowSupForm(false);
    setDone('support');
    setTimeout(() => setDone(''), 3000);
  };

  const handleRemoveSupport = (name) => {
    ctrl.updateItem(want.id, (cur) => ({
      ...cur, supporters: (cur.supporters || []).filter(s => s.name !== name)
    }));
  };

  const handleSendGift = () => {
    const name = giftSender.trim().slice(0, 20);
    if (!name || !selectedGift) return;
    const gift = gifts[selectedGift];
    if (!gift) return;
    try { localStorage.setItem('mn_penname', name); } catch {}
    ctrl.updateItem(want.id, (cur) => ({
      ...cur,
      gifts: [...(cur.gifts || []), {
        giftEntryId: `g_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        sender: name,
        giftId: gift.id,
        giftName: gift.name,
        emoji: gift.emoji,
        at: Date.now(),
        paid: false
      }]
    }));
    setShowGiftForm(false);
    setSelectedGift('');
    setDone('gift');
    setTimeout(() => setDone(''), 3000);
  };

  const handleDelete = () => {
    ctrl.removeItem(want.id);
    onBack();
  };

  return (
    <div style={s.boardScreen}>
      <div style={s.boardContainer}>
        <button onClick={onBack} style={s.backBtn}>← 一覧に戻る</button>

        <div style={{ ...s.detailCard, borderTopColor: C.yellow }}>
          {want.photo && <img src={want.photo} alt="" style={s.detailPhoto}/>}
          <div style={s.wantRegionTag}>📍 {want.regionLabel}</div>
          <h2 style={{ ...s.detailTitle, marginTop: 8 }}>{want.want}</h2>
          <div style={s.detailMetaRow}><span style={s.detailMetaLabel}>👤 投稿者</span><span>{want.penname}</span></div>
          {(want.ageGroup || want.gender) && (
            <div style={s.detailMetaRow}>
              <span style={s.detailMetaLabel}>🏷 属性</span>
              <span>{[want.ageGroup, want.gender].filter(Boolean).join(' / ')}</span>
            </div>
          )}
        </div>

        {/* 応援者 */}
        <div style={s.participantSection}>
          <div style={s.participantHead}>
            <h3 style={s.participantTitle}><span style={{ ...s.featureDot, background: C.yellow }}/>応援している人</h3>
            <span style={{ ...s.participantCount, background: C.yellowLight, color: '#C87F0A' }}>{supporters.length}人</span>
          </div>
          {supporters.length === 0 ? (
            <div style={s.participantEmpty}>まだ応援がありません。最初の応援者になろう！</div>
          ) : (
            <div style={s.chipList}>
              {supporters.map((sp, idx) => (
                <div key={`${sp.name}_${sp.at}`} style={{ ...s.chip, background: [C.yellowLight, C.pinkLight, C.greenLight][idx%3], borderColor: [C.yellow, C.pink, C.green][idx%3] }}>
                  <span>🙌 {sp.name}</span>
                  <button onClick={() => handleRemoveSupport(sp.name)} style={s.chipRemove}>×</button>
                </div>
              ))}
            </div>
          )}
          {!showSupForm && done !== 'support' && (
            <button onClick={() => setShowSupForm(true)} style={{ ...s.joinBtn, background: C.yellow, boxShadow: '0 3px 0 #C87F0A' }}>
              <span style={{ fontSize: '1.25rem' }}>🙌</span><span>応援する</span>
            </button>
          )}
          {showSupForm && (
            <div style={{ ...s.joinForm, borderColor: C.yellow }}>
              <label style={s.joinFormLabel}>ペンネームを入力してください</label>
              <div style={{ display: 'flex', gap: 8, marginBottom: 8 }}>
                <input type="text" value={supName} onChange={(e) => setSupName(e.target.value)} placeholder="例：ほっくさん" maxLength={20} style={s.input} autoFocus/>
                <button onClick={handleSupport} disabled={!supName.trim()} style={{ ...s.joinFormBtn, background: C.yellow }}>応援</button>
              </div>
              <button onClick={() => setShowSupForm(false)} style={s.joinFormCancel}>キャンセル</button>
            </div>
          )}
          {done === 'support' && (
            <div style={{ ...s.toast, background: C.yellowLight }}>
              <span style={{ fontSize: '1.5rem' }}>🙌</span>
              <div><div style={s.toastTitle}>応援しました！</div><div style={s.toastSub}>気持ちが届きました</div></div>
            </div>
          )}
        </div>

        {/* 応援ギフト */}
        <div style={s.participantSection}>
          <div style={s.participantHead}>
            <h3 style={s.participantTitle}><span style={{ ...s.featureDot, background: C.pink }}/>応援ギフト</h3>
            <span style={{ ...s.participantCount, background: C.pinkLight, color: C.pink }}>{sentGifts.length}件</span>
          </div>
          {sentGifts.length === 0 ? (
            <div style={s.participantEmpty}>クラフトビールを贈って応援できます🍺</div>
          ) : (
            <div style={s.giftReceivedList}>
              {sentGifts.map((g, idx) => (
                <div key={g.giftEntryId || idx} style={s.giftReceivedItem}>
                  <span style={{ fontSize: '1.375rem' }}>{g.emoji || '🎁'}</span>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={s.giftReceivedName}>{g.giftName}</div>
                    <div style={s.giftReceivedSender}>from {g.sender}</div>
                  </div>
                  <span style={{
                    ...s.payBadge,
                    background: g.paid ? C.greenLight : C.yellowLight,
                    color: g.paid ? C.greenDark : '#C87F0A',
                    border: `1px solid ${g.paid ? C.green : C.yellow}`
                  }}>
                    {g.paid ? '✓ お会計済' : '○ お会計未'}
                  </span>
                </div>
              ))}
            </div>
          )}
          {!showGiftForm && done !== 'gift' && (
            <button onClick={() => setShowGiftForm(true)} style={{ ...s.joinBtn, background: C.pink, boxShadow: '0 3px 0 #B0005F' }}>
              <span style={{ fontSize: '1.25rem' }}>🎁</span><span>応援ギフトを送る</span>
            </button>
          )}
          {showGiftForm && (
            <div style={{ ...s.joinForm, borderColor: C.pink }}>
              <label style={s.joinFormLabel}>贈るクラフトビールを選んでください</label>
              <div style={s.giftSelectGrid}>
                {giftList.map(g => (
                  <button key={g.id} onClick={() => setSelectedGift(g.id)} style={{
                    ...s.giftOption,
                    ...(selectedGift === g.id ? { borderColor: g.color, background: g.color + '15', boxShadow: `0 2px 0 ${g.color}` } : {})
                  }}>
                    {g.photo
                      ? <img src={g.photo} alt="" style={s.giftOptionPhoto}/>
                      : <div style={{ fontSize: '1.875rem' }}>{g.emoji}</div>}
                    <div style={s.giftOptionName}>{g.name}</div>
                    <div style={s.giftOptionDesc}>{g.description}</div>
                  </button>
                ))}
              </div>
              <label style={{ ...s.joinFormLabel, marginTop: 12 }}>あなたのペンネーム</label>
              <div style={{ display: 'flex', gap: 8, marginBottom: 8 }}>
                <input type="text" value={giftSender} onChange={(e) => setGiftSender(e.target.value)} placeholder="例：たんめぐさん" maxLength={20} style={s.input}/>
                <button onClick={handleSendGift} disabled={!giftSender.trim() || !selectedGift} style={{ ...s.joinFormBtn, background: C.pink }}>贈る</button>
              </div>
              <button onClick={() => { setShowGiftForm(false); setSelectedGift(''); }} style={s.joinFormCancel}>キャンセル</button>
            </div>
          )}
          {done === 'gift' && (
            <div style={{ ...s.toast, background: C.pinkLight }}>
              <span style={{ fontSize: '1.5rem' }}>🎁</span>
              <div><div style={s.toastTitle}>ギフトを贈りました！</div><div style={s.toastSub}>お会計はカウンターでお願いします🍺</div></div>
            </div>
          )}
        </div>

        <div style={{ display: 'flex', justifyContent: 'center', marginTop: 24 }}><DeleteBtn onConfirm={handleDelete} label="この投稿を削除"/></div>
      </div>
    </div>
  );
}

// =====================================
// 【3】こんな街になったらいいな
// =====================================
function CityHopesBoard({ cityHopes, ctrl, onBack }) {
  const [creating, setCreating] = useState(false);
  const [detailId, setDetailId] = useState(null);

  if (creating) {
    return <CityHopeCreate onSubmit={(c) => { ctrl.addItem(c); setCreating(false); }} onCancel={() => setCreating(false)}/>;
  }
  if (detailId) {
    const c = cityHopes.find(x => x.id === detailId);
    if (!c) { setDetailId(null); return null; }
    return <CityHopeDetail hope={c} ctrl={ctrl} onBack={() => setDetailId(null)}/>;
  }

  return (
    <div style={s.boardScreen}>
      <div style={s.boardContainer}>
        <button onClick={onBack} style={s.backBtn}>← 掲示板トップ</button>
        <header style={{ textAlign: 'center', marginBottom: 24 }}>
          <div style={{ fontSize: '2.5rem' }}>🌸</div>
          <h1 style={{ ...s.boardTitle, fontSize: '1.5rem' }}>こんな街になったらいいな</h1>
          <p style={s.boardSubtitle}>街への思いをシェアしよう</p>
          <AccentLine style={{ width: 60, margin: '16px auto 0' }} />
        </header>

        <button onClick={() => setCreating(true)} style={{ ...s.bigActionBtn, background: C.pink, boxShadow: '0 3px 0 #B0005F' }}>
          <span style={s.bigActionIcon}>＋</span>
          <span>街への思いを書く</span>
        </button>

        {cityHopes.length === 0 ? (
          <div style={s.boardEmpty}>
            <div style={{ fontSize: '3rem' }}>🏘️</div>
            <div style={s.boardEmptyTitle}>まだ投稿がありません</div>
            <div style={s.boardEmptySub}>あなたの街への思いを最初に書こう</div>
          </div>
        ) : (
          <div style={s.cardList}>
            {cityHopes.map((c, idx) => {
              const color = [C.pink, C.green, C.yellow][idx % 3];
              const empathy = c.empathy || [];
              return (
                <button key={c.id} onClick={() => setDetailId(c.id)} style={{ ...s.eventCard, borderLeftColor: color }}>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    {c.photo && <img src={c.photo} alt="" style={s.cardThumb}/>}
                    <div style={s.wantRegionTag}>📍 {c.regionLabel}</div>
                    <div style={s.eventCardTitle}>{c.hope}</div>
                    <div style={s.eventCardMeta}>
                      <span>by {c.penname}</span>
                      <span style={{ ...s.joinPill, background: color + '20', color }}>💗 {empathy.length}</span>
                    </div>
                  </div>
                </button>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

function CityHopeCreate({ onSubmit, onCancel }) {
  const [hope, setHope] = useState('');
  const [penname, setPenname] = useState('');
  const [region, setRegion] = useState('');
  const [photo, setPhoto] = useState(null);
  const [ageGroup, setAgeGroup] = useState('');
  const [gender, setGender] = useState('');
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('mn_penname');
    if (saved) setPenname(saved);
  }, []);

  const canSubmit = hope.trim() && penname.trim() && region && !submitting;

  const handleSubmit = () => {
    if (!canSubmit) return;
    setSubmitting(true);
    try { localStorage.setItem('mn_penname', penname); } catch {}
    onSubmit({
      id: `hope_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
      hope: hope.trim().slice(0, 140),
      penname: penname.trim().slice(0, 20),
      region: region,
      regionLabel: regionLabelFromValue(region),
      photo: photo || null,
      ageGroup: ageGroup || null,
      gender: gender || null,
      empathy: [],
      timestamp: Date.now()
    });
  };

  return (
    <div style={s.boardScreen}>
      <div style={s.boardContainer}>
        <button onClick={onCancel} style={s.backBtn}>← 戻る</button>
        <header style={{ textAlign: 'center', marginBottom: 24 }}>
          <h1 style={{ ...s.boardTitle, fontSize: '1.375rem' }}>街への思いを書く</h1>
          <AccentLine style={{ width: 60, margin: '12px auto 0' }} />
        </header>

        <div style={s.field}>
          <label style={s.label}><span style={{ ...s.labelDot, background: C.pink }} />街への気持ち<span style={s.required}>必須</span></label>
          <textarea value={hope} onChange={(e) => setHope(e.target.value)} placeholder="例：もっと世代を超えて話せる場所が増えたらいいな" maxLength={140} rows={4} style={s.textarea}/>
          <div style={s.charCount}>{hope.length} / 140</div>
        </div>

        <div style={s.field}>
          <label style={s.label}><span style={{ ...s.labelDot, background: C.green }} />ペンネーム<span style={s.required}>必須</span></label>
          <input type="text" value={penname} onChange={(e) => setPenname(e.target.value)} placeholder="例：みなみさん" maxLength={20} style={s.input}/>
        </div>

        <div style={s.field}>
          <label style={s.label}><span style={{ ...s.labelDot, background: C.yellow }} />地域<span style={s.required}>必須</span></label>
          <RegionSelect value={region} onChange={setRegion}/>
        </div>

        <OptionalFields photo={photo} setPhoto={setPhoto} ageGroup={ageGroup} setAgeGroup={setAgeGroup} gender={gender} setGender={setGender}/>

        <button onClick={handleSubmit} disabled={!canSubmit} style={{ ...s.submitBtn, background: C.pink, boxShadow: '0 3px 0 #B0005F', opacity: canSubmit ? 1 : 0.45, cursor: canSubmit ? 'pointer' : 'not-allowed' }}>
          <span>{submitting ? '掲示中…' : '掲示板に貼る'}</span>
          {!submitting && <span style={{ fontSize: '1.125rem' }}>→</span>}
        </button>
      </div>
    </div>
  );
}

function CityHopeDetail({ hope, ctrl, onBack }) {
  const [empName, setEmpName] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [done, setDone] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('mn_penname');
    if (saved) setEmpName(saved);
  }, []);

  const empathy = hope.empathy || [];

  const handleEmpathize = () => {
    const name = empName.trim().slice(0, 20);
    if (!name) return;
    if (empathy.some(e => e.name === name)) { alert('すでに共感済みです'); return; }
    try { localStorage.setItem('mn_penname', name); } catch {}
    ctrl.updateItem(hope.id, (cur) => ({
      ...cur, empathy: [...(cur.empathy || []), { name, at: Date.now() }]
    }));
    setShowForm(false);
    setDone(true);
    setTimeout(() => setDone(false), 3000);
  };

  const handleRemove = (name) => {
    ctrl.updateItem(hope.id, (cur) => ({
      ...cur, empathy: (cur.empathy || []).filter(e => e.name !== name)
    }));
  };

  const handleDelete = () => {
    ctrl.removeItem(hope.id);
    onBack();
  };

  return (
    <div style={s.boardScreen}>
      <div style={s.boardContainer}>
        <button onClick={onBack} style={s.backBtn}>← 一覧に戻る</button>

        <div style={{ ...s.detailCard, borderTopColor: C.pink }}>
          {hope.photo && <img src={hope.photo} alt="" style={s.detailPhoto}/>}
          <div style={s.wantRegionTag}>📍 {hope.regionLabel}</div>
          <h2 style={{ ...s.detailTitle, marginTop: 8 }}>{hope.hope}</h2>
          <div style={s.detailMetaRow}><span style={s.detailMetaLabel}>👤 投稿者</span><span>{hope.penname}</span></div>
          {(hope.ageGroup || hope.gender) && (
            <div style={s.detailMetaRow}>
              <span style={s.detailMetaLabel}>🏷 属性</span>
              <span>{[hope.ageGroup, hope.gender].filter(Boolean).join(' / ')}</span>
            </div>
          )}
        </div>

        <div style={s.participantSection}>
          <div style={s.participantHead}>
            <h3 style={s.participantTitle}><span style={{ ...s.featureDot, background: C.pink }}/>同じ気持ちの人</h3>
            <span style={{ ...s.participantCount, background: C.pinkLight, color: C.pink }}>{empathy.length}人</span>
          </div>
          {empathy.length === 0 ? (
            <div style={s.participantEmpty}>まだ共感がありません。最初の一人になろう！</div>
          ) : (
            <div style={s.chipList}>
              {empathy.map((e, idx) => (
                <div key={`${e.name}_${e.at}`} style={{ ...s.chip, background: [C.pinkLight, C.greenLight, C.yellowLight][idx%3], borderColor: [C.pink, C.green, C.yellow][idx%3] }}>
                  <span>💗 {e.name}</span>
                  <button onClick={() => handleRemove(e.name)} style={s.chipRemove}>×</button>
                </div>
              ))}
            </div>
          )}
          {!showForm && !done && (
            <button onClick={() => setShowForm(true)} style={{ ...s.joinBtn, background: C.pink, boxShadow: '0 3px 0 #B0005F' }}>
              <span style={{ fontSize: '1.25rem' }}>💗</span><span>同じ気持ち！</span>
            </button>
          )}
          {showForm && (
            <div style={{ ...s.joinForm, borderColor: C.pink }}>
              <label style={s.joinFormLabel}>ペンネームを入力してください</label>
              <div style={{ display: 'flex', gap: 8, marginBottom: 8 }}>
                <input type="text" value={empName} onChange={(e) => setEmpName(e.target.value)} placeholder="例：はるもさん" maxLength={20} style={s.input} autoFocus/>
                <button onClick={handleEmpathize} disabled={!empName.trim()} style={{ ...s.joinFormBtn, background: C.pink }}>共感</button>
              </div>
              <button onClick={() => setShowForm(false)} style={s.joinFormCancel}>キャンセル</button>
            </div>
          )}
          {done && (
            <div style={{ ...s.toast, background: C.pinkLight }}>
              <span style={{ fontSize: '1.5rem' }}>💗</span>
              <div><div style={s.toastTitle}>共感しました！</div><div style={s.toastSub}>気持ちが届きました</div></div>
            </div>
          )}
        </div>

        <div style={{ display: 'flex', justifyContent: 'center', marginTop: 24 }}><DeleteBtn onConfirm={handleDelete} label="この投稿を削除"/></div>
      </div>
    </div>
  );
}

// =====================================
// ルート
// =====================================
export default function App() {
  const [view, setView] = useState('map');
  const [isCustomer, setIsCustomer] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const { posts, addPost, removePost, removeAllPosts, updatePost } = usePosts();
  const { stores, saveStore, deleteStore } = useStores();
  const { settings, updateSettings } = useSettings();
  // 掲示板3機能
  const eventsCtrl = useBoard(KEYS.events, 'events');
  const wantsCtrl = useBoard(KEYS.wants, 'wants');
  const cityHopesCtrl = useBoard(KEYS.cityHopes, 'cityhopes');
  const { gifts, saveGift, deleteGift } = useGifts();
  const { tags, addTag, updateTag, deleteTag, moveTag } = useTags();

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const v = params.get('view');
    const customer = params.get('customer') === '1';
    const admin = params.get('admin') === '1';

    setIsCustomer(customer);
    setIsAdmin(admin || !customer);

    if (v && ['map', 'board', 'qr', 'admin'].includes(v)) {
      if (customer && v === 'admin') {
        setView('map');
      } else {
        setView(v);
      }
    }
  }, []);

  // タブ構成
  const tabs = [];
  if (settings.showMap) tabs.push({ key: 'map', icon: '🗾', label: 'マップ' });
  if (settings.showBoard) tabs.push({ key: 'board', icon: '📋', label: '掲示板' });
  if (isAdmin && settings.showQR) tabs.push({ key: 'qr', icon: '📱', label: 'QR' });
  if (isAdmin) tabs.push({ key: 'admin', icon: '⚙️', label: '管理' });

  useEffect(() => {
    if (!tabs.some(t => t.key === view)) {
      setView('map');
    }
    // eslint-disable-next-line
  }, [view, isAdmin, settings.showQR, settings.showMap, settings.showBoard]);

  // 文字サイズ：管理画面のみ適用。スマホ（customer）はブラウザデフォルトのまま
  useEffect(() => {
    if (isCustomer) {
      document.documentElement.style.fontSize = '';
      return;
    }
    const scale = FONT_SIZE_ZOOM[settings.fontSize || '中'];
    document.documentElement.style.fontSize = `${28.8 * scale}px`;
    return () => { document.documentElement.style.fontSize = ''; };
  }, [settings.fontSize, isCustomer]);

  // お客様モード：フォームのみ表示
  if (isCustomer) {
    return <CustomerPostPage posts={posts} addPost={addPost} updatePost={updatePost} stores={stores} tags={tags} settings={settings}/>;
  }

  return (
    <div style={{ minHeight: '100vh', fontFamily: FONT_BODY, background: C.bgWhite, color: C.ink }}>
      <div style={s.switcher}>
        {tabs.map(t => (
          <button key={t.key} onClick={() => setView(t.key)} style={{ ...s.switcherBtn, ...(view === t.key ? s.switcherBtnActive : {}) }}>
            <span>{t.icon}</span>
            <span style={{ fontSize: '0.6875rem', fontWeight: 600 }}>{t.label}</span>
          </button>
        ))}
        <div style={s.totalBadge}>{posts.length}</div>
        {isCustomer && (
          <div style={{
            background: C.green, color: '#fff',
            fontFamily: FONT_HAND, fontSize: '0.625rem', fontWeight: 700,
            padding: '4px 10px', borderRadius: 999, marginLeft: 4, letterSpacing: 1
          }}>
            👋 ゲスト
          </div>
        )}
      </div>

      {view === 'map' && <MapView posts={posts} addPost={addPost} updatePost={updatePost} stores={stores} tags={tags} settings={settings} updateSettings={updateSettings}/>}
      {view === 'board' && (
        <BoardScreen
          events={eventsCtrl.items} eventsCtrl={eventsCtrl}
          wants={wantsCtrl.items} wantsCtrl={wantsCtrl}
          cityHopes={cityHopesCtrl.items} cityHopesCtrl={cityHopesCtrl}
          gifts={gifts}
          stores={stores}
          settings={settings}
        />
      )}
      {view === 'qr' && isAdmin && <QRScreen/>}
      {view === 'admin' && isAdmin && (
        <AdminScreen
          posts={posts}
          removePost={removePost}
          removeAllPosts={removeAllPosts}
          updatePost={updatePost}
          stores={stores}
          saveStore={saveStore}
          deleteStore={deleteStore}
          settings={settings}
          updateSettings={updateSettings}
          events={eventsCtrl.items} eventsCtrl={eventsCtrl}
          wants={wantsCtrl.items} wantsCtrl={wantsCtrl}
          cityHopes={cityHopesCtrl.items} cityHopesCtrl={cityHopesCtrl}
          gifts={gifts} saveGift={saveGift} deleteGift={deleteGift}
          tags={tags} addTag={addTag} updateTag={updateTag} deleteTag={deleteTag} moveTag={moveTag}
        />
      )}
    </div>
  );
}

